response:
```json
{
  "Cargo.toml": "[dependencies]
crossterm = "0.27"
",
  "main.rs": "use crossterm::event::{self, Event, KeyCode, KeyEventKind};
use std::io::{self, Write};
use std::time::{Duration, Instant};

fn main() -> io::Result<()> {
    println!("Starting event loop. Press 'q' to quit.");
    println!("Now the 'tick' message should appear every second, regardless of key presses.\n");

    let mut last_tick = Instant::now();
    let tick_rate = Duration::from_secs(1);

    loop {
        // Calculate time until next tick to use as poll timeout
        let time_since_last_tick = last_tick.elapsed();

        // If we've passed the tick rate, use 0 timeout (return immediately)
        // otherwise wait only as long as needed for the next tick
        let timeout = if time_since_last_tick >= tick_rate {
            Duration::from_secs(0)
        } else {
            tick_rate - time_since_last_tick
        };

        // Poll for events with the calculated timeout
        // This is non-blocking - it returns after `timeout` if no event is available
        if event::poll(timeout)? {
            // An event is available - read it
            let event = event::read()?;

            println!("- Event received: {:?}", event);

            if let Event::Key(key) = event {
                // Check for 'q' key press to quit
                if key.code == KeyCode::Char('q') && key.kind == KeyEventKind::Press {
                    println!("'q' pressed, quitting.");
                    break;
                }
            }
        }

        // Check if it's time for a tick
        // This runs when poll times out (no event) OR after processing an event
        if last_tick.elapsed() >= tick_rate {
            println!("Tick!");
            io::stdout().flush()?;
            last_tick = Instant::now();
        }
    }

    Ok(())
}
"
}
