use syn::{parse_macro_input, DeriveInput, Attribute, Meta, Lit};

// ============ Notion API Types ============

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct RichTextObject {
