// ============ NotionProperty Attribute Parsing ============

#[derive(Clone)]
struct NotionPropertyAttr {
    prop_type: String,
    name: String,
}

fn parse_notion_property_attr(attr: &Attribute) -> Option<NotionPropertyAttr> {
    let meta = attr.parse_meta().ok()?;
    if let Meta::List(list) = meta {
        if list.path.is_ident("notion_property") {
            let mut prop_type = String::new();
            let mut name = String::new();

            for nested in list.nested {
                if let Meta::NameValue(nv) = nested {
                    if nv.path.is_ident("type") {
                        if let Lit::Str(lit) = nv.lit {
                            prop_type = lit.value();
                        }
                    } else if nv.path.is_ident("name") {
                        if let Lit::Str(lit) = nv.lit {
                            name = lit.value();
                        }
                    }
                }
            }

            if !prop_type.is_empty() && !name.is_empty() {
                return Some(NotionPropertyAttr { prop_type, name });
            }
        }
    }
    None
}

// ============ Custom Derive Macro ============

#[proc_macro_derive(NotionProperty, attributes(notion_property))]
pub fn notion_property_derive(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let struct_name = input.ident;
    let (impl_generics, ty_generics, where_clause) = input.generics.split_for_impl();

    // Collect field information
    let fields: Vec<_> = input.data
        .as_struct()
        .expect("Expected a struct")
        .fields
        .iter()
        .enumerate()
        .filter_map(|(i, field)| {
            let field_name = field.ident.clone().unwrap_or_else(|| syn::Ident::new(&format!("__field{}", i), proc_macro2::Span::call_site()));
            let field_ty = field.ty.clone();

            let attr = field.attrs.iter().find_map(parse_notion_property_attr);

            attr.map(|a| (field_name, field_ty, a))
        })
        .collect();

    // Generate the conversion code
    let field_inserts: Vec<_> = fields.iter().map(|(field_name, field_ty, attr)| {
        let key = &attr.name;
        let prop_type = &attr.prop_type;

        match prop_type.as_str() {
            "title" => {
                quote! {
                    tmp.insert(#key.to_string(), PropertyValues::Title(
                        vec![RichTextObject {
                            annotations: None,
                            data_type: Some("text".to_string()),
                            equation: None,
                            mention: None,
                            plain_text: None,
                            href: None,
                            text: Some(TextObject {
                                content: self.#field_name.clone(),
                                link: None,
                            }),
                        }]
                    ));
                }
            }
            "url" => {
                quote! {
                    if let Some(val) = self.#field_name.clone() {
                        tmp.insert(#key.to_string(), PropertyValues::Url(val));
                    }
                }
            }
            "MultiSelect" => {
                quote! {
                    if let Some(vals) = self.#field_name.clone() {
                        tmp.insert(#key.to_string(), PropertyValues::MultiSelect(
                            vals.iter().map(|f| SelectObject {
                                id: None,
                                color: None,
                                name: format!("{}", f),
                            }).collect()
                        ));
                    }
                }
            }
            "Select" => {
                quote! {
                    if let Some(val) = self.#field_name.clone() {
                        tmp.insert(#key.to_string(), PropertyValues::Select(SelectObject {
                            id: None,
                            color: None,
                            name: val,
                        }));
                    }
                }
            }
            "checkbox" => {
                quote! {
                    tmp.insert(#key.to_string(), PropertyValues::Checkbox(self.#field_name));
                }
            }
            "number" => {
                quote! {
                    tmp.insert(#key.to_string(), PropertyValues::Number(self.#field_name));
                }
            }
            "date" => {
                quote! {
                    if let Some(val) = self.#field_name.clone() {
                        tmp.insert(#key.to_string(), PropertyValues::Date(val));
                    }
                }
            }
            "email" => {
                quote! {
                    if let Some(val) = self.#field_name.clone() {
                        tmp.insert(#key.to_string(), PropertyValues::Email(val));
                    }
                }
            }
            "phone_number" => {
                quote! {
                    if let Some(val) = self.#field_name.clone() {
                        tmp.insert(#key.to_string(), PropertyValues::PhoneNumber(val));
                    }
                }
            }
            "rich_text" => {
                quote! {
                    if let Some(val) = self.#field_name.clone() {
                        tmp.insert(#key.to_string(), PropertyValues::RichText(val));
                    }
                }
            }
            _ => {
                quote! {
                    // Default: try to serialize as JSON value
                    tmp.insert(#key.to_string(), PropertyValues::Other);
                }
            }
        }
    }).collect();

    let expanded = quote! {
        impl #impl_generics NotionProperty for #struct_name #ty_generics #where_clause {
            fn to_notion_properties(&self) -> HashMap<String, PropertyValues> {
                let mut tmp = HashMap::new();
                #(#field_inserts)*
