    #[notion_property(type = "checkbox", name = "Active")]
    pub is_active: bool,

    #[notion_property(type = "number", name = "Priority")]
    pub priority: f64,
}

fn main() {
    // Create an instance of our struct
    let unit = MyUnit {
        name: "Test Item".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec![
