    // Convert to Notion HashMap
    let props = unit.to_notion_properties();

    // Print the result as JSON
    println!("Generated Notion Properties:");
    println!("{}", serde_json::to_string_pretty(&props).unwrap());

    // Verify some expected values
    println!("\n--- Verification ---");

    if let Some(PropertyValues::Title(title)) = props.get("Name") {
        if let Some(text) = title.first().and_then(|r| r.text.as_ref()) {
            println!("Name property: {}", text.content);
