    if let Some(PropertyValues::Url(url)) = props.get("Icon url") {
        println!("Icon URL property: {}", url);
    }

    if let Some(PropertyValues::MultiSelect(multi)) = props.get("Roles") {
        println!("Roles property: {:?}", multi.iter().map(|s| &s.name).collect::<Vec<_>>());
    }

    if let Some(PropertyValues::Checkbox(b)) = props.get("Active") {
        println!("Active property: {}", b);
    }

    if let Some(PropertyValues::Number(n)) = props.get("Priority") {
        println!("Priority property: {}", n);
    }

    println!("\nSuccess! The struct was converted to a Notion-compatible HashMap.");
}"
}
