  "main.rs": "use std::env;
use std::fs;
use std::io::Write;
use std::process::Command;

fn main() {
    // Embed the Python script at compile time
    // This path is relative to the crate root (where Cargo.toml is)
    let script_bytes = include_bytes!("src/python/script.py");

    // Get the temporary directory
    let temp_dir = env::temp_dir();

    // Create a unique filename to avoid collisions
    let pid = std::process::id();
    let timestamp = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .subsec_nanos();
    let script_filename = format!("rust_program_script_{}_{}.py", pid, timestamp);
    let script_path = temp_dir.join(script_filename);

    // Write the embedded script to the temporary file
    let mut file = fs::File::create(&script_path).expect("Failed to create temporary script file");
    file.write_all(script_bytes)
        .expect("Failed to write script to temporary file");

    // Determine the Python interpreter command
    let python_cmd = if cfg!(target_os = "windows") {
        // On Windows, try 'py' first (Python Launcher), then 'python'
        if Command::new("py").arg("--version").output().is_ok() {
            "py"
        } else if Command::new("python").arg("--version").output().is_ok() {
            "python"
        } else {
            eprintln!("Error: Python interpreter not found on Windows");
            fs::remove_file(&script_path).ok();
            std::process::exit(1);
        }
    } else {
        // On Unix-like systems, try 'python3' first, then 'python'
        if Command::new("python3").arg("--version").output().is_ok() {
            "python3"
        } else if Command::new("python").arg("--version").output().is_ok() {
            "python"
        } else {
            eprintln!("Error: Python interpreter not found on Unix-like system");
            fs::remove_file(&script_path).ok();
            std::process::exit(1);
        }
    };

    // Execute the Python script
    let output = Command::new(python_cmd)
        .arg(&script_path)
        .output()
        .expect("Failed to execute Python script");

    // Print the output from the Python script
    if !output.stdout.is_empty() {
        print!("{}", String::from_utf8_lossy(&output.stdout));
    }
    if !output.stderr.is_empty() {
        eprint!("{}", String::from_utf8_lossy(&output.stderr));
    }

    // Clean up the temporary script file
    if let Err(e) = fs::remove_file(&script_path) {
        eprintln!("Warning: Failed to remove temporary script file: {}", e);
    }

    // Exit with the same status code as the Python script
    std::process::exit(output.status.code().unwrap_or(1));
}
"
}
