/// Custom layer that checks the Origin header for WebSocket upgrades.
/// This wraps a handler and validates the origin before allowing the upgrade.
fn check_origin_layer(
    allowed_origin: HeaderValue,
) -> impl Fn(axum::routing::Route) -> axum::routing::Route + Clone {
    let allowed_origin = allowed_origin;
    move |mut route: axum::routing::Route| {
        let allowed_origin = allowed_origin.clone();
        axum::routing::Route::new().fallback(move |req: axum::extract::Request| {
            let allowed_origin = allowed_origin.clone();
            async move {
                // Only check origin for WebSocket upgrade requests
                if let Some(origin_header) = req.headers().get("origin") {
                    if origin_header != &allowed_origin {
                        return (StatusCode::FORBIDDEN, "Origin not allowed").into_response();
                    }
                }
                // For WebSocket, also check the "sec-websocket-origin" header (used by some clients)
                else if let Some(ws_origin) =
                    req.headers().get(HeaderName::from_static("sec-websocket-origin"))
                {
                    if ws_origin != &allowed_origin {
                        return (StatusCode::FORBIDDEN, "Origin not allowed").into_response();
                    }
                }

                // Pass through to the actual handler
                route.call(req).await
            }
        })
    }
}

async fn handle_socket(
    ws: WebSocketUpgrade,
    ConnectInfo(addr): ConnectInfo<SocketAddr>,
) -> Response {
    println!("New WebSocket connection from: {}", addr);

    let origin = ws
        .request
        .headers()
        .get("origin")
        .map(|v| v.to_str().unwrap_or(""))
        .unwrap_or("");

    println!("Origin: {}", origin);

    ws.on_upgrade(|socket| async move {
        println!("WebSocket upgrade complete");
        // Handle the WebSocket connection here
        use axum::extract::WebSocket;
        let mut ws = WebSocket::new(socket, addr);
        if let Some(msg) = ws.recv().await {
            println!("Received: {:?}", msg);
        }
    })
    .into_response()
}

async fn client_handler(ws: WebSocketUpgrade) -> Response {
    handle_socket(ws, ConnectInfo(SocketAddr::from((127, 0, 0, 1)))).await
}

#[tokio::main]
async fn main() {
    // Initialize tracing
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::from_default_env()
                .add_directive(tracing::Level::INFO.into()),
        )
        .init();

    let allowed_origin = "https://www.example.com"
        .parse::<HeaderValue>()
        .expect("Failed to parse allowed origin");

    let cors = CorsLayer::new()
        .allow_origin(allowed_origin.clone())
        .allow_methods([Method::GET, Method::POST])
        .allow_headers(headers::HeaderName::from_static("content_type"));

