#[tauri::command]
fn spawn_agent(app: AppHandle, state: tauri::State<AppState>) -> Result<(), String> {
    // Check if already running
    if state.pty_tx.lock().unwrap().is_some() {
        return Err("Agent already running".into());
    }

    // 1. Create PTY
    let pty_system = native_pty_system();
    let pair = pty_system
        .openpty(PtySize {
            rows: 24,
            cols: 80,
            pixel_width: 0,
            pixel_height: 0,
        })
        .map_err(|e| e.to_string())?;

