    // This is the CRITICAL step. We must set the PTY file descriptor to non-blocking
    // so that `read` returns immediately if there is no data, allowing us to check
    // the write channel.
    let master = pair.master;
    let fd = master.as_raw_fd();
    unsafe {
        let flags = fcntl(fd, FcntlArg::F_GETFL).map_err(|e| e.to_string())?;
        let _ = fcntl(fd, FcntlArg::F_SETFL(flags | O_NONBLOCK));
    }

    // 4. Split the MasterPty into Reader and Writer
    // We take ownership of the reader/writer to move them into the thread.
    let mut reader = master.try_clone_reader().map_err(|e| e.to_string())?;
    let mut writer = master.take_writer().map_err(|e| e.to_string())?;

    // 5. Create Communication Channel
    let (tx, rx) = channel::unbounded::<PtyCommand>();

    // 6. Save Sender to State
    *state.pty_tx.lock().unwrap() = Some(tx);

