    // This thread handles both reading from the PTY and writing to it.
    // It never blocks indefinitely on I/O.
    thread::spawn(move || {
        // Buffer for reading
        let mut buf = [0u8; 1024];

        // We use `poll` to wait for the FD to be readable, or a timeout.
        // We also check the `rx` channel.
        // Since `poll` only works on FDs, we use a timeout to periodically check the channel
        // if no data is coming in.

        loop {
            // A. Check for pending commands (non-blocking try_recv)
            match rx.try_recv() {
                Ok(PtyCommand::Write(data)) => {
                    // If write fails (e.g., process died), we could emit an error,
                    // but typically we just ignore or log.
                    let _ = writer.write_all(data.as_bytes());
                    let _ = writer.flush();
