#[derive(Debug)]
enum Message {
    /// A key press event.
    Key(Key),
    /// A captured signal (e.g. SIGINT, SIGTERM).
    Signal(i32),
    /// Request to shut down the whole program.
    Stop,
}

fn main() {
    // ------------------------------------------------------------
    // Communication channel: threads send messages to the main loop
    // ------------------------------------------------------------
    let (msg_tx, msg_rx): (Sender<Message>, Receiver<Message>) = mpsc::channel();

    // ------------------------------------------------------------
    // A shared flag that can be used to signal the worker threads
    // to stop as soon as possible.
    // ------------------------------------------------------------
    let stop_flag = Arc::new(AtomicBool::new(false));

    // ------------------------------------------------------------
    // Thread 1: listen for Unix signals (SIGINT, SIGTERM)
    // ------------------------------------------------------------
    let signal_tx = msg_tx.clone();
    let stop_for_signal = stop_flag.clone();
    thread::spawn(move || {
        // Register the signals we want to listen to
        let signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

        // `forever()` blocks until a signal is received. After each signal
        // we forward it to the main loop and then check the stop flag.
        for sig in signals.forever() {
            let _ = signal_tx.send(Message::Signal(sig));

            // If we have been asked to stop, close the signal handle so the
            // iterator terminates immediately and we can exit the loop.
            if stop_for_signal.load(Ordering::SeqCst) {
                signals.handle().close();
                break;
            }
        }
    });

    // ------------------------------------------------------------
    // Thread 2: listen for key presses (using termion)
    // ------------------------------------------------------------
    let key_tx = msg_tx.clone();
    let stop_for_key = stop_flag.clone();
    thread::spawn(move || {
        // Lock stdin – termion expects a `Read` object.
        let stdin = io::stdin();
        let mut stdin = stdin.lock();

        // `stdin.events()` yields `Result<Event, io::Error>`.
        for evt in stdin.events() {
            match evt {
                Ok(event) => {
                    // We only care about key events.
                    if let Event::Key(key) = event {
                        let _ = key_tx.send(Message::Key(key));
                    }
                }
                Err(_) => {
                    // Any read error (e.g. EOF) stops the loop.
                    break;
                }
            }

            // After handling each event, see whether we have been told to stop.
            if stop_for_key.load(Ordering::SeqCst) {
                break;
            }
        }
    });

    // ------------------------------------------------------------
    // Main event loop: process messages from the two worker threads
    // ------------------------------------------------------------
    loop {
        match msg_rx.recv() {
            Ok(msg) => match msg {
                Message::Key(key) => {
                    println!("Received key: {:?}", key);
                    // Press 'q' to request shutdown.
                    if key == Key::Char('q') {
                        println!("'q' pressed – initiating shutdown");
                        stop_flag.store(true, Ordering::SeqCst);
                        let _ = msg_tx.send(Message::Stop);
                    }
                }
                Message::Signal(sig) => {
                    println!("Received signal: {}", sig);
                    // For any caught signal we also initiate shutdown.
                    stop_flag.store(true, Ordering::SeqCst);
                    let _ = msg_tx.send(Message::Stop);
                }
                Message::Stop => {
                    println!("Stop message received – exiting main loop.");
                    break;
                }
            },
            Err(_) => {
                // The channel was closed – this should not happen in normal use.
                break;
            }
        }
    }

    // ------------------------------------------------------------
    // Clean up – the spawned threads will exit as soon as they see the
    // stop flag set and process the last event (if any).
    // ------------------------------------------------------------
    println!("Program terminated.");
}
"
}
