enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll the given future to completion without awaiting it.
/// Returns `Ready` if the future completed on this poll, otherwise `Pending`.
fn try_poll<X>(future: &mut impl Future<Output = X>) -> TryPollResult<X>
where
    X: Unpin,
{
    // Obtain a no-op waker. This waker does nothing when woken, which is fine
    // because we only need to check whether the future is ready right now.
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.poll(&mut cx) {
        Poll::Ready(v) => TryPollResult::Ready(v),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    // Example 1: a future that completes immediately.
    let mut fut1 = async { 42 };
    match try_poll(&mut fut1) {
        TryPollResult::Ready(v) => {
            println!("Future 1 ready immediately: {}", v);
        }
        TryPollResult::Pending => {
            // This won't happen for this future.
            println!("Future 1 pending (unexpected)");
        }
    }

    // Example 2: a future that returns Pending on the first poll.
    let fut2 = async {
        // Yield control to the runtime so the future will be Pending on the
        // first poll.
        tokio::time::sleep(std::time::Duration::from_millis(50)).await;
        "hello"
    };
    // We need `fut2` to be `Unpin` to pass it as `&mut impl Future`.
    // The `async` block is `Unpin` because it doesn't contain !Unpin fields.
    let mut fut2 = fut2;

    match try_poll(&mut fut2) {
        TryPollResult::Ready(v) => {
            // This would be surprising – it would mean the timer already fired.
            println!("Future 2 ready prematurely: {}", v);
        }
        TryPollResult::Pending => {
            println!("Future 2 was pending on first poll, spawning a task...");

            // Spawn a new task to drive the future to completion.
            let handle = tokio::spawn(async move {
                fut2.await
            });

            // The handle can be awaited to obtain the final result.
            let result = handle.await.expect("task panicked");
            println!("Spawned task returned: {}", result);
        }
    }

    // Example 3: a helper that combines the two steps.
    async fn example_helper() {
        // A future that needs a few yields before completion.
        let mut future = async {
            tokio::time::sleep(std::time::Duration::from_millis(10)).await;
            123i32
        };

        // Try to complete it without spawning.
        match try_poll(&mut future) {
            TryPollResult::Ready(v) => {
                println!("Helper: completed without spawn: {}", v);
            }
            TryPollResult::Pending => {
                println!("Helper: pending, spawning task...");
                let handle = tokio::spawn(async move {
                    future.await
                });
                let value = handle.await.expect("task panicked");
                println!("Helper: got value from spawned task: {}", value);
            }
        }
    }

    example_helper().await;

    // Keep the runtime alive a little longer to allow any spawned tasks to finish.
    tokio::time::sleep(std::time::Duration::from_millis(100)).await;
    println!("All examples finished.");
}
