use std::sync::mpsc::{channel, Sender};
use std::thread;

// The context that will be passed to the async workloads.
pub struct Context(pub i32);

// The message that can be sent across threads.
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
            + Send,
        >,
    },
}

// A wrapper that turns a `FnOnce` which returns a `Send` future
// into a `Fn` (required for the channel).
struct FnOnceWrapper<F> {
    inner: Mutex<Option<F>>,
}

impl<F, Fut> Fn(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> for FnOnceWrapper<F>
where
    F: FnOnce(&mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    fn call(&self, ctx: &mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
        // Extract the closure (we only call it once).
        let block = self.inner.lock().unwrap().take()
            .expect("the async workload can only be executed once");
        // Turn the closure into a future.
        let fut = block(ctx);
        // Pin the future and coerce to a trait object.
        Box::pin(fut) as _
    }
}

/// Helper that builds an `InnerAsyncEvent` from an async closure.
/// 
/// The closure must be `Send` and return a future that is also `Send`.
pub fn with_context_async<F, Fut>(block: F) -> InnerAsyncEvent
where
    F: FnOnce(&mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    let wrapper = FnOnceWrapper {
        inner: Mutex::new(Some(block)),
    };
    InnerAsyncEvent::DoWithContext {
        block: Box::new(wrapper),
    }
}

fn main() {
    // Create a channel for the async events.
    let (tx, rx): (Sender<InnerAsyncEvent>, _) = channel();

    // Spawn a worker thread that will receive and execute the async workloads.
    let worker = thread::spawn(move || {
        // We need a Tokio runtime to await the future.
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .unwrap();

        // Process incoming events.
        for event in rx {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    rt.block_on(async {
                        let mut ctx = Context(0);
                        let fut = block(&mut ctx);
                        fut.await;
                        // After the future completes, the context has been modified.
                        println!("Result after async block: {}", ctx.0);
                    });
                }
            }
        }
    });

    // Create an async workload using the convenient helper.
    let event = with_context_async(move |ctx: &mut Context| {
        async move {
            ctx.0 += 1;
            println!("Inside async block, ctx.0 = {}", ctx.0);
        }
    });

    // Send the workload to the worker.
    tx.send(event).unwrap();
    drop(tx); // Close the sender so the worker can exit its loop.

    // Wait for the worker to finish.
    worker.join().unwrap();
}
"
}
