    // Print stdout.
    if !output.stdout.is_empty() {
        print!(\"{}\", String::from_utf8_lossy(&output.stdout));
    }
    // Print stderr if any.
    if !output.stderr.is_empty() {
        eprint!(\"{}\", String::from_utf8_lossy(&output.stderr));
    }

    if !output.status.success() {
        anyhow::bail!(\"Python script exited with status: {}\", output.status);
    }

    Ok(())
}

/// Tries to find a Python interpreter (python3, python) available on the system.
