    }

    pub fn get_nb(&self) -> Vec<usize> {
        unsafe { (&*self.nb.get()).clone() }
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Sequential version without unsafe pointer
    /// Modifies both elem_i and elem_j when criterion is met
    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();

        // Clear all neighbor lists
        for elem in &self.elems {
            elem.clear_nb();
        }

        // Iterate over all pairs
        for i in 0..nelems {
            for j in 0..nelems {
                if i != j {
                    if self.elems[i].criterion(&self.elems[j]) < self.cutoff {
                        // Modify both elements
                        self.elems[i].push_nb(j);
                        self.elems[j].push_nb(i);
                    }
                }
            }
        }
    }

    /// Parallel version using rayon
    /// Uses two-pass approach: first collect pairs in parallel, then apply sequentially
    pub fn build_lists_parallel(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // Clear all neighbor lists
        for elem in &self.elems {
            elem.clear_nb();
        }

        // First pass: collect all pairs that satisfy the criterion in parallel
        // We create a reference to elems to use in the parallel closure
        let elems = &self.elems;

        let pairs: Vec<(usize, usize)> = (0..nelems)
            .into_par_iter()
            .flat_map(|i| {
                let mut local_pairs = Vec::new();
                for j in 0..nelems {
                    if i != j && elems[i].criterion(&elems[j]) < cutoff {
                        local_pairs.push((i, j));
                    }
                }
                local_pairs
            })
            .collect();

        // Second pass: apply modifications to both elements
        // This is sequential but fast (just push operations)
        for (i, j) in pairs {
            self.elems[i].push_nb(j);
            self.elems[j].push_nb(i);
        }
    }
}

