use rustyline::error::ReadlineError;

fn main() -> Result<()> {
    // Create the editor.
    let mut rl = DefaultEditor::new()?;

    // Prompt for a new (toplevel) input.
    let mut prompt = ">> ";

    loop {
        // `readline` prints the prompt, then lets the user edit the current
        // input buffer.  If the buffer already contains text (e.g., after a
        // newline was inserted) the user continues editing that same buffer.
        let readline = rl.readline(prompt);

        match readline {
            Ok(line) => {
                // Remove trailing whitespace – we only care about the final
                // character(s) for deciding whether the input is complete.
                let line = line.trim_end();

                // Simple rule: a line that ends with a semicolon is a complete
                // statement; anything else continues the multiline input.
                if line.ends_with(';') {
                    // Statement is complete – evaluate it (here we just print).
                    println!("Evaluated: {}", line);

                    // Reset the prompt to the toplevel one.
                    prompt = ">> ";
                } else {
                    // Incomplete – the next call to `readline` will display a
                    // continuation prompt.  The previously entered text stays
                    // in the editing buffer, so the user can keep typing.
                    prompt = "... ";
                }
            }
            Err(ReadlineError::Eof) => {
                // Ctrl‑D (or EOF) exits the REPL.
                break;
            }
            Err(err) => {
                eprintln!("Error: {:?}", err);
                break;
            }
        }
    }

    Ok(())
}
