fn extract_econtent_from_signeddata(der_data: &[u8]) -> Result<Vec<u8>, der::Error> {
    // Parse ContentInfo
    // ContentInfo ::= SEQUENCE { contentType, content [0] }
    let reader = &mut SliceReader::new(der_data)?;
    let _content_type: der::Oid = reader.read()?;

    // Read the explicit tag [0]
    let _ = reader.read_tag(Tag::Context0)?;
    let signed_data_len = reader.len()?;
    let signed_data_start = reader.position();

    // We are now at the start of SignedData.
    // SignedData ::= SEQUENCE { version, digestAlgorithms, encapContentInfo, ... }

    // Parse Sequence header
    reader.read_tag(Tag::Sequence)?;
    let signed_data_content_len = reader.len()?;
    let signed_data_end = signed_data_start + signed_data_content_len + 2; // +2 for tag and len of Seq

    // 1. Skip Version (INTEGER)
    reader.read()?; // tag
    let ver_len = reader.len()?;
    reader.skip(ver_len)?;

    // 2. Skip DigestAlgorithms (SET OF)
    reader.read()?; // tag
    let da_len = reader.len()?;
    reader.skip(da_len)?;

    // 3. Parse EncapsulatedContentInfo
    // EncapsulatedContentInfo ::= SEQUENCE { eContentType, eContent [0] }
    reader.read_tag(Tag::Sequence)?;
    let eci_len = reader.len()?;
    let eci_end = reader.position() + eci_len;

    // eContentType (OID)
    reader.read()?; // tag
    let _ect_len = reader.len()?;
    reader.skip(reader.len()?)?;

    // Check for eContent [0] EXPLICIT
    if reader.position() < eci_end {
        let tag = reader.read()?;
        if tag == Tag::Context0 {
            let content_len = reader.len()?;

            // eContent is OCTET STRING
            reader.read_tag(Tag::OctetString)?;
            let octet_len = reader.len()?;

            // Extract the bytes
            let payload = reader.read_bytes(octet_len as usize)?;
            return Ok(payload.to_vec());
        }
    }

    Err(der::Error::UnexpectedEof)
}
