fn DraggablePoint(props: DraggablePointProps) -> Element {
    // Local state for the position of this specific point
    let mut position = use_signal(|| (props.initial_x, props.initial_y));

    // Local state to track if THIS specific point is being dragged
    let mut is_local_dragging = use_signal(|| false);

    // Consume the global drag context
    let drag_state = use_context::<DragState>();

    // Use an effect to react to global drag events.
    // This replaces the "ugly" logic inside the render body.
    // It runs whenever the tracked signals (dependencies) change.
    use_effect(move || {
        let is_dragging_global = drag_state.is_dragging.read();
        let mouse_pos = drag_state.mouse_position.read();

        // If the global drag is active AND this specific point initiated the drag
        if *is_dragging_global && *is_local_dragging.read() {
            if let Some(pos) = mouse_pos {
                // Update local position based on global mouse coordinates
                // (In a full app, you'd calculate the offset from where the click started)
                position.set(pos);
            }
        }

        // Cleanup: If global drag stops, reset local drag state
        if !*is_dragging_global {
            is_local_dragging.set(false);
        }
    });

    rsx! {
        circle {
            cx: position.read().0,
            cy: position.read().1,
            r: 20,
            fill: props.color,
            stroke: "black",
            stroke_width: 2,
            cursor: "pointer",

            // Start dragging this point on mousedown
            onmousedown: move |_evt| {
                is_local_dragging.set(true);
                // Note: We don't need to manually set global is_dragging here 
                // because the parent provider already catches the bubbling event 
                // and sets it to true.
            }
        }
    }
}
