use azure_storage_blobs::prelude::*;
use futures::stream::{StreamExt, FuturesUnordered};
use reqwest::Client;
use serde::{Deserialize, Serialize};
use std::env;
use std::sync::Arc;
use tokio::sync::Semaphore;

// Simple TradeData struct - adjust fields based on your JSON structure
