pub struct TradeData {
    // Add your fields here, for example:
    // pub id: Option<String>,
    // pub name: Option<String>,
    // etc.
}

#[derive(Serialize)]
struct TokenRequest<'a> {
    grant_type: &'a str,
    client_id: &'a str,
    client_secret: &'a str,
    scope: &'a str,
}

#[derive(Deserialize)]
struct TokenResponse {
    access_token: String,
}

async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error + Send + Sync>> {
    let token_url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        tenant_id
    );

    let client = Client::new();
    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    let response = client
        .post(&token_url)
        .form(&params)
        .send()
        .await?;

    if !response.status().is_success() {
        let body = response.text().await.unwrap_or_default();
        return Err(format!("Token request failed: {}", body).into());
    }

    let token_response: TokenResponse = response.json().await?;
    Ok(token_response.access_token)
}

// Process blobs with proper parallelism using semaphore
async fn process_blobs_parallel(
    container_client: &ContainerClient,
    prefix: String,
    semaphore: Arc<Semaphore>,
) -> Vec<TradeData> {
    let mut all_trades = Vec::new();
    let mut stream = container_client.list_blobs().prefix(prefix.clone()).into_stream();

    // Collect all blob names first
    let mut all_blob_names = Vec::new();
    while let Some(response) = stream.next().await {
        if let Ok(response) = response {
            for blob in response.blobs.blobs() {
                if blob.name.ends_with(".json") {
                    all_blob_names.push(blob.name.clone());
                }
            }
        }
    }

    // Now download all in parallel with semaphore limit
    let mut futures = FuturesUnordered::new();

    for blob_name in all_blob_names {
        let container_client = container_client.clone();
        let semaphore = semaphore.clone();

        futures.push(async move {
            let _permit = semaphore.acquire().await.expect("Semaphore acquire failed");
            let blob_client = container_client.blob_client(&blob_name);

            match blob_client.get_content().await {
                Ok(data) => match serde_json::from_slice::<TradeData>(&data) {
                    Ok(trade) => Some(trade),
                    Err(e) => {
                        eprintln!("Failed to parse {}: {}", blob_name, e);
                        None
                    }
                },
                Err(e) => {
                    eprintln!("Failed to download {}: {}", blob_name, e);
                    None
                }
            }
        });
    }

    while let Some(result) = futures.next().await {
        if let Some(trade) = result {
            all_trades.push(trade);
        }
    }

    all_trades
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let start = std::time::Instant::now();
    println!("Starting Azure Blob download...");

    // Get environment variables
    let tenant_id = env::var("AZURE_TENANT_ID")?;
    let client_id = env::var("AZURE_CLIENT_ID")?;
    let client_secret = env::var("AZURE_CLIENT_SECRET")?;
    let storage_account = env::var("AZURE_ACCOUNT_NAME")?;
    let container_name = env::var("AZURE_CONTAINER_NAME")?;
    let prefix_opt = env::var("AZURE_PREFIX_OPT")?;
    let prefix_fut = env::var("AZURE_PREFIX_FUT")?;

