    let auth_start = std::time::Instant::now();
    let token = get_oauth_token(&tenant_id, &client_id, &client_secret).await?;
    println!("Authentication took: {:.2}s", auth_start.elapsed().as_secs_f32());

    // Create credentials and clients
    let credentials = StorageCredentials::bearer_token(token);
    let blob_service = BlobServiceClient::new(storage_account, credentials);
    let container_client = blob_service.container_client(container_name);

    // Use semaphore to limit concurrent downloads (similar to C#'s MaxDegreeOfParallelism)
    let num_cpus = std::thread::available_parallelism()
        .map(|p| p.get())
        .unwrap_or(4);
    let semaphore = Arc::new(Semaphore::new(num_cpus * 2)); // Allow 2x CPU count for I/O bound work

    println!("Using {} max concurrent downloads", num_cpus * 2);

    // Process both prefixes in parallel
    let download_start = std::time::Instant::now();
    let (trades_opt, trades_fut) = futures::join!(
        process_blobs_parallel(&container_client, prefix_opt, semaphore.clone()),
        process_blobs_parallel(&container_client, prefix_fut, semaphore.clone()),
    );

    let mut all_trades = trades_opt;
    all_trades.extend(trades_fut);

    println!("Downloading took: {:.2}s", download_start.elapsed().as_secs_f32());
    println!("Total time: {:.2}s", start.elapsed().as_secs_f32());
    println!("Downloaded {} trades", all_trades.len());

    Ok(())
}
"
}
