use core::sync::atomic::{AtomicUsize, Ordering};
use critical_section::with;
use panic_halt as _;

pub struct Channel {
    index: AtomicUsize,
}

impl Channel {
    pub const fn new() -> Self {
        Self {
            index: AtomicUsize::new(0),
        }
    }

    /// Returns the next unique index, using a critical section to
    /// emulate `fetch_add` with relaxed ordering.
    ///
    /// Because the critical section guarantees exclusive access, the
 /// relaxed ordering is sufficient – it matches the semantics of the
    /// original `fetch_add(..., Ordering::Relaxed)`. The critical section
    /// itself acts as an acquire/release barrier, so no additional memory
    /// ordering primitives are required.
    pub fn next_index(&self) -> usize {
        with(|_cs| {
            let old = self.index.load(Ordering::Relaxed);
            self.index.store(old.wrapping_add(1), Ordering::Relaxed);
            old
        })
    }
}

