/// Tokenizes a shell command respecting single‑quote quoting.
///
/// Whitespace outside quotes separates tokens; whitespace inside quotes
/// is preserved. The quote characters themselves are not part of the token.
fn tokenize(s: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;

    for ch in s.chars() {
        if ch == '\'' {
            // Toggle the quoted state; the quote character itself is omitted.
            in_single_quote = !in_single_quote;
        } else if in_single_quote {
            // Inside single quotes we keep everything (including whitespace).
            current.push(ch);
        } else {
            // Outside quotes we treat whitespace as a token separator.
            if ch.is_whitespace() {
                if !current.is_empty() {
                    tokens.push(current);
                    current = String::new();
                }
                // otherwise skip additional whitespace
            } else {
                current.push(ch);
            }
        }
    }

    // Push the final token if it exists.
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    // If a command line argument is given, use it as the input string.
    // Otherwise, fall back to the example from the problem statement.
