struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a B variant (First, Second, or Third)")
    }

    fn visit_map<V>(self, mut map: V) -> Result<Self::Value, V::Error>
    where
        V: MapAccess<'de>,
    {
        // For enums in JSON, they typically come as {"VariantName": value}
        // We need to get the first (and only) key to determine which variant it is
        let key: String = map
            .next_key()?
            .ok_or_else(|| de::Error::missing_field("variant name"))?;

        match key.as_str() {
            "First" => {
                let value: String = map.next_value()?;
                Ok(B::First(value))
            }
            "Second" => {
                let value: usize = map.next_value()?;
                Ok(B::Second(value))
            }
            "Third" => {
                // For the Third variant which has named fields,
                // we need to deserialize the inner map
                #[derive(Deserialize)]
                struct ThirdInner {
                    value: i32,
                }
                let inner: ThirdInner = map.next_value()?;
                Ok(B::Third { value: inner.value })
            }
            _ => Err(de::Error::unknown_variant(&key, &["First", "Second", "Third"])),
        }
    }
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        // Deserialize as a map since our enum representation uses map syntax
        deserializer.deserialize_map(BVisitor)
    }
}

// Struct A containing a Vec<B>
#[derive(Debug, PartialEq)]
struct A {
    x: usize,
    b: Vec<B>,
}

impl Default for A {
    fn default() -> Self {
        A { x: 0, b: Vec::new() }
    }
}

// Custom visitor for struct A
struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("struct A with fields 'x' and 'b'")
    }

    fn visit_map<V>(self, mut map: V) -> Result<Self::Value, V::Error>
    where
