  "main.rs": "use std::ops::Range;
use std::sync::Arc;
use serde::Deserialize;

/// The borrowed struct we want to deserialize into.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// A cheap, self‑contained representation that stores indices into the
/// original JSON string instead of direct references. This makes the type
/// `Send` and `Clone` (the latter because it just clones the `Arc`).
#[derive(Debug, Clone)]
pub struct MyDataRef {
    source: Arc<String>,
    data_range: Range<usize>,
    more_data_range: Range<usize>,
}

impl MyDataRef {

    /// Parse a JSON string into a `MyDataRef`. This performs the
    /// deserialization once and then converts the borrowed `&str` fields
    /// into index ranges that are safe to move across task boundaries.
    pub fn parse(json: String) -> Result<Self, serde_json::Error> {
        // Obtain a temporary borrow of the string for the deserializer.
        let json_str: &str = &json;

        // Deserialize into the borrowed struct.
        let borrowed: MyData = serde_json::from_str(json_str)?;

        // Compute the offsets of each field relative to the start of the
        // original buffer. We do this before moving the `String` into an
        // `Arc`.
        let base_ptr = json.as_ptr();

        let data_ptr = borrowed.data.as_ptr();
        let more_data_ptr = borrowed.more_data.as_ptr();

        let data_start = data_ptr as usize - base_ptr as usize;
        let data_end = data_start + borrowed.data.len();

        let more_data_start = more_data_ptr as usize - base_ptr as usize;
        let more_data_end = more_data_start + borrowed.more_data.len();

        // Wrap the original string in an `Arc` so that the data can be
        // shared cheaply between tasks.
        let source = Arc::new(json);

        Ok(MyDataRef {
            source,
            data_range: data_start..data_end,
            more_data_range: more_data_start..more_data_end,
        })
    }

    /// Access the `data` field as a `&str`.
    pub fn data(&self) -> &str {
        &self.source[self.data_range.clone()]
    }

    /// Access the `more_data` field as a `&str`.
    pub fn more_data(&self) -> &str {
        &self.source[self.more_data_range.clone()]
    }
}

#[tokio::main]
async fn main() {
    // Create a channel to simulate incoming JSON payloads.
    let (tx, mut rx) = tokio::sync::mpsc::channel::<String>(10);

    // Producer: send a JSON payload.
    let json_payload = "{\"data\":\"hello\",\"more_data\":\"world\"}".to_string();
    tx.send(json_payload).await.expect("send ok");

    // Close the sender so the receiver will eventually terminate.
    drop(tx);

    // Consumer: receive JSON strings, parse once, and forward the
    // resulting `MyDataRef` to a new task.
    while let Some(json) = rx.recv().await {
        match MyDataRef::parse(json) {
            Ok(parsed) => {
                // Move the parsed structure into a new task.
                tokio::spawn(async move {
                    // The task can now read the fields without any
                    // additional deserialization or cloning.
                    println!("data      = {}", parsed.data());
                    println!("more_data = {}", parsed.more_data());
                });
            }
            Err(e) => {
                eprintln!("parse error: {}", e);
            }
        }
    }

    // Give the spawned tasks a moment to finish.
    tokio::time::sleep(std::time::Duration::from_millis(100)).await;
}
