Instruction: Your deliverables is a Cargo.toml file and a main.rs file that's self-contained so I can move them into a rust project and test it with `cargo run`. Only return a json object with the following keys: - Cargo.toml: the contents of the Cargo.toml file - main.rs: the contents of the main.rs file

response:
Looking at this problem, I need to create a custom trait that wraps `AsyncFnOnce` and explicitly requires the output future to be `Send`. This solves the core issue: the standard `AsyncFnOnce` trait doesn't constrain the `Send`-ness of its output future, so the compiler can't verify it's safe to send across threads.

Here's the solution:

```json
{
  "Cargo.toml": "[package]
name = "async-thread-wrapper"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
futures = "0.3"
",
  "main.rs": "use std::future::{Future, Pin};

// Example context type
pub struct Context(pub i32);

// The message type for the channel - holds the boxed async work
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
            + Send,
        >,
    },
}

// Custom trait: Combines AsyncFnOnce with requirement that output future is Send
// This is the key to solving the problem!
pub trait AsyncFnOnceSend<'a, T>: Send {
    type Future: Future<Output = ()> + Send + 'a;
    fn call_once(self, arg: T) -> Self::Future;
}

// Blanket implementation for any async closure that meets the bounds
// This allows users to pass simple async closures without complex setup
impl<'a, T, F, Fut> AsyncFnOnceSend<'a, T> for F
where
    F: AsyncFnOnce<T, Output = Fut> + Send + 'a,
    Fut: Future<Output = ()> + Send + 'a,
{
    type Future = Fut;

    fn call_once(self, arg: T) -> Self::Future {
        AsyncFnOnce::call_once(self, arg)
    }
}

// The user's desired API - simple and clean!
pub fn with_context_async(
    work_sender: std::sync::mpsc::Sender<InnerAsyncEvent>,
    block: impl for<'a> AsyncFnOnceSend<'a, &'a mut Context> + Send + 'static,
) {
    // Convert from our custom trait to the boxed dyn Fn trait
    let block = move |ctx: &mut Context| {
        let fut = block.call_once(ctx);
        // Explicitly pin the future - the Send bound is now guaranteed
        Box::pin(fut) as Pin<Box<dyn Future<Output = ()> + Send + '_>>
    };

    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(block),
    });
}

// ============================================================================
// Test code below
// ============================================================================

use std::thread;
use std::sync::mpsc;

#[tokio::main]
async fn main() {
    println!("Testing async closure passing between threads...\n");

    // Create a channel for sending work between threads
    let (tx, rx) = mpsc::channel::<InnerAsyncEvent>();

    // Spawn a worker thread that will receive and execute async work
    let handle = thread::spawn(move || {
        // The worker thread runs its own tokio runtime
        tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .unwrap()
            .block_on(async {
                // Receive the async work
                match rx.recv() {
                    Ok(event) => {
                        let mut ctx = Context(0);
                        let fut = match event {
                            InnerAsyncEvent::DoWithContext { block } => block(&mut ctx),
                        };
                        fut.await;
                        println!("Worker: Context value after async work: {}", ctx.0);
                    }
                    Err(e) => eprintln!("Worker: Failed to receive: {:?}", e),
                }
            });
    });

    // Send an async closure to the worker thread
    // This is now simple and clean!
    with_context_async(tx, async move |ctx: &mut Context| {
        // This async block captures nothing (or only Send types)
        // so the resulting future is Send
        ctx.0 += 1;
        println!("  (inside async) incrementing context");
    });

    // Wait for worker to finish
    handle.join().unwrap();

    println!("\nSuccess! The async closure was successfully sent between threads.");
}
"
}
```

