Looking at this problem, the key issue is that you need to capture the parent span when it's active and then "rehydrate" (make current) when your stage functions are called later on potentially different threads.

The solution involves:
1. Capturing `Span::current()` at the point where the parent span exists
2. Storing a clone of that span (spans are `Clone + Send + Sync`)
3. Using `.in_scope()` to execute code within that span's context when the stage functions are invoked

Here's a complete working example:

```json
{
  "Cargo.toml": "[package]
name = "tracing-otel-rehydrate"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
tracing = "0.1"
tracing-subscriber = { version = "0.3", features = ["env-filter"] }
tracing-otlp = "0.3"
opentelemetry = { version = "0.21", features = ["trace"] }
opentelemetry-otlp = "0.14"
futures = "0.3"

[profile.dev]
opt-level = 0
debug = true

[profile.release]
opt-level = 3
debug = false
",
  "main.rs": "// Example demonstrating how to rehydrate spans in Rust tracing/OpenTelemetry
// This pattern is useful when you need to maintain span context across
// async boundaries or when functions are called on different threads.

use std::sync::Arc;
use tokio::sync::RwLock;
use tracing::{info, warn, Span, field};
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

// ============================================================================
// Core Pattern: Context that carries the span
// ============================================================================

/// A request context that carries the parent span from the original
/// request context. This allows us to rehydrate the span later when
/// stage functions are actually executed.
#[derive(Clone)]
pub struct RequestContext {
    /// The parent span that was active when the request started.
    /// Spans are Clone + Send + Sync, so we can share this across
    /// threads and async tasks.
    parent_span: Span,

    /// Additional request metadata
    request_id: String,
}

impl RequestContext {
    /// Create a new request context, capturing the CURRENT span as the parent.
    /// This should be called at the point where the request enters your system.
    pub fn new(request_id: String) -> Self {
        // Key insight: Span::current() captures whatever span is currently active
        let parent_span = Span::current();

        // Add some metadata to the span for correlation
        parent_span.record("request_id", &request_id);

        Self {
            parent_span,
            request_id,
        }
    }

    /// Create from an explicitly provided parent span (useful for testing)
    pub fn with_span(request_id: String, span: Span) -> Self {
        Self {
            parent_span: span,
            request_id,
        }
    }

    /// Get the request ID
    pub fn request_id(&self) -> &str {
        &self.request_id
    }

    // ========================================================================
    // THE KEY METHOD: Rehydrate and execute within the parent span
    // ========================================================================

    /// Execute an async function within the parent span's context.
    /// This is how you "rehydrate" the span - by using in_scope() to
    /// make the parent span current for the duration of the async block.
    /// 
    /// All spans created inside `future` will become children of parent_span.
    pub async fn in_parent_scope<F, T>(&self, future: F) -> T
    where
        F: std::future::Future<Output = T>,
    {
        // in_scope() makes the span current for the duration of the closure.
        // All Span::current() calls inside will return parent_span.
        // This works across await points because the span is tied to the
        // current tracing context, not the call stack.
        self.parent_span.in_scope(future).await
    }

    /// Synchronous version of in_parent_scope
    pub fn in_parent_scope_sync<F, T>(&self, f: F) -> T
    where
        F: std::ops::FnOnce() -> T,
    {
        self.parent_span.in_scope(f)
    }

    /// Create a child span that will be a child of the parent span.
    /// This is useful when you want explicit child spans rather than
    /// relying on Span::current().
    pub fn child_span(&self, name: &'static str) -> tracing::Span {
        // When we enter this span, it automatically becomes a child
        // of parent_span because parent_span is currently active
        // (via in_scope or because we're already in parent_scope)
        tracing::info_span!(name, request_id = %self.request_id)
    }
}

// ============================================================================
// Trait that represents your stage functions (like in Pingora)
// ============================================================================

/// Trait representing a stage in request processing
/// Each stage can be called with a context that carries the parent span
pub trait RequestStage: Send + Sync {
    fn name(&self) -> &'static str;

    /// Process the request stage. The context carries the parent span.
    fn process(&self, ctx: RequestContext) -> impl std::future::Future<Output = Result<(), String>> + Send;
}

// ============================================================================
// Concrete stage implementations
// ============================================================================

pub struct StageOne;

impl RequestStage for StageOne {
    fn name(&self) -> &'static str {
        "stage_1"
    }

    async fn process(&self, ctx: RequestContext) -> Result<(), String> {
        // This span will be a child of the parent span because we're
        // executing within in_parent_scope
        let span = tracing::info_span!("stage_1_execution");

        span.in_scope(|| {
            info!(stage = "stage_1", "Stage 1 starting");
        });

        // Simulate some async work
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

        span.in_scope(|| {
            info!(stage = "stage_1", "Stage 1 completed");
        });

        Ok(())
    }
}

pub struct StageTwo;

impl RequestStage for StageTwo {
    fn name(&self) -> &'static str {
        "stage_2"
    }

    async fn process(&self, ctx: RequestContext) -> Result<(), String> {
        let span = tracing::info_span!("stage_2_execution");

        span.in_scope(|| {
            info!(stage = "stage_2", "Stage 2 starting");
        });

        // Simulate some async work
        tokio::time::sleep(tokio::time::Duration::from_millis(150)).await;

        span.in_scope(|| {
            info!(stage = "stage_2", "Stage 2 completed");
        });

        Ok(())
    }
}

pub struct UpstreamStage {
    pub upstream_host: String,
}

impl RequestStage for UpstreamStage {
    fn name(&self) -> &'static str {
        "upstream"
    }

    async fn process(&self, ctx: RequestContext) -> Result<(), String> {
        let span = tracing::info_span!(
            "upstream_request",
            upstream_host = %self.upstream_host
        );

        span.in_scope(|| {
            info!(stage = "upstream", "Making upstream request");
        });

        // Simulate upstream request
        tokio::time::sleep(tokio::time::Duration::from_millis(200)).await;

        span.in_scope(|| {
            info!(stage = "upstream", "Upstream response received");
        });

        Ok(())
    }
}

// ============================================================================
// Request processor that orchestrates the stages
// ============================================================================

/// Simulates the Pingora request handling
pub struct RequestProcessor {
    stages: Vec<Box<dyn RequestStage>>,
}

impl RequestProcessor {
    pub fn new() -> Self {
        Self {
            stages: Vec::new(),
        }
    }

    pub fn add_stage(mut self, stage: impl RequestStage + 'static) -> Self {
        self.stages.push(Box::new(stage));
        self
    }

    /// Process a request through all stages
    /// This is where we'd capture the parent span at the "top" of the request
    pub async fn process_request(&self, request_id: String) {
        // =========================================================================
        // KEY STEP 1: Create the parent span at the entry point
        // This is where the request first enters your system
        // =========================================================================
        let request_span = tracing::info_span!(
            "request",
            request_id = %request_id,
            "request.type" = "http"
        );

        // Enter the span - now it's the current span
        let _guard = request_span.enter();

        info!("Starting request processing");

        // =========================================================================
        // KEY STEP 2: Create context with the CURRENT (parent) span
        // ========================================================================
        let ctx = RequestContext::new(request_id);

        // Process all stages
        for stage in &self.stages {
            // Execute each stage within the parent scope
            // This ensures all child spans created in stages are children
            // of the original request span, not just the immediate parent
            if let Err(e) = ctx.in_parent_scope(stage.process(ctx.clone())).await {
                warn!("Stage failed: {}", e);
                break;
            }
        }

        info!("Request processing complete");
    }
}

// ============================================================================
// Demonstration of the problem and solution
// ============================================================================

/// This demonstrates the common mistake and how to fix it
mod anti_patterns {
    use tracing::Span;

    /// ANTI-PATTERN: This doesn't work because Span::enter() only works
    /// for the lifetime of the guard, not across await points or threads
    pub fn wrong_approach() {
        let span = Span::current();
        let _guard = span.enter();
        // The span is NO LONGER active after _guard is dropped!
        // Any await point will lose the span context
    }

    /// CORRECT: Use in_scope for async operations or use tracing::Instrument
    pub async fn correct_approach<F, T>(span: Span, future: F) -> T
    where
        F: std::future::Future<Output = T>,
    {
        // in_scope makes the span current for the entire future execution
        span.in_scope(future).await
    }
}

// ============================================================================
// Main entry point
// ============================================================================

#[tokio::main]
async fn main() {
    // Initialize tracing with a simple console subscriber
    // In production, you'd use opentelemetry-otlp to export to Jaeger/OTLP
    tracing_subscriber::registry()
        .with(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "tracing_otel_rehydrate=debug,tokio=info".into()),
        )
        .with(tracing_subscriber::fmt::layer())
        .init();

    info!("Starting tracing otel rehydration demo");

    // Create a processor with stages
    let processor = RequestProcessor::new()
        .add_stage(StageOne)
        .add_stage(StageTwo)
        .add_stage(UpstreamStage {
            upstream_host: "example.com".to_string(),
        });

    // Simulate multiple concurrent requests
    let mut handles = vec![];

    for i in 1..=3 {
        let processor = RequestProcessor::new()
            .add_stage(StageOne)
            .add_stage(StageTwo)
            .add_stage(UpstreamStage {
                upstream_host: format!("example{}", i),
            });

        let handle = tokio::spawn(async move {
            processor.process_request(format!("req-{}", i)).await;
        });

        handles.push(handle);
    }

    // Wait for all requests to complete
    for handle in handles {
        handle.await.unwrap();
    }

    info!("All requests completed");

    // Print explanation
    println!("\n========================================");
    println!("KEY CONCEPTS FOR REHYDRATING SPANS:");
    println!("========================================\n");
    println!("1. Capture the parent span at the entry point using Span::current()");
    println!("2. Store a clone of the Span (it is Clone + Send + Sync)");
    println!("3. When executing code in your stage functions, use .in_scope()");
    println!("   to make the parent span current for the duration of the async work");
    println!("\nExample:");
    println!("  self.parent_span.in_scope(async {").
    println!("      // All spans created here are children of parent_span").
    println!("  }).await");
    println!("\nThis ensures the span hierarchy:");
    println!("  |-- Request/Parent Span -----------------------|");
    println!("    |-- Stage 1 Span --|");
    println!("                       |-- Stage 2 Span --|");
    println!("                                      |-- Upstream --|");
}
"
}
