#[derive(Debug)]
enum FlusterError {
    FailToParseDate,
}

type FlusterResult<T> = Result<T, FlusterError>;

/// Attempts to parse an ISO‑8601 date string that may or may not contain
/// fractional seconds. Returns a `DateTime<Utc>`.
fn parse_iso(s: &str) -> FlusterResult<DateTime<Utc>> {
    let s = s.trim();

    // First try with fractional seconds (e.g. "2025-08-02T17:35:41.409")
    if let Ok(ndt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%T%.f") {
        return Ok(ndt.and_utc());
    }

    // Fallback to parsing without fractional seconds (e.g. "1970-01-01T00:00:00")
    if let Ok(ndt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%T") {
        return Ok(ndt.and_utc());
    }

    Err(FlusterError::FailToParseDate)
}

/// Converts a LanceDB‑style date string to a Unix timestamp (seconds since
/// the epoch).
pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    let dt = parse_iso(d)?;
    Ok(dt.timestamp())
}

