use std::future::Future;
use std::pin::Pin;
use std::boxed::Box;
use futures::executor::block_on;

// ---------------------------------------------------------------------------
// Request / Response types
// ---------------------------------------------------------------------------
#[derive(Clone, Debug, Send, Sync)]
pub struct Request(pub String);

#[derive(Clone, Debug, Send, Sync)]
pub struct Response(pub String);

impl Response {
    pub fn new(s: impl Into<String>) -> Self {
        Response(s.into())
    }
}

// ---------------------------------------------------------------------------
// Handler trait – abstracts over both sync and async functions
// ---------------------------------------------------------------------------
pub trait Handler: Send + Sync {
    /// Call the handler with the given request.
    /// The returned future is required to be `Send` and is tied to the
    /// lifetime of the request (`'_`).
    fn call(
        &self,
        req: &Request,
    ) -> Pin<Box<dyn Future<Output = Response> + Send + '_>>;
}

// Implementation for synchronous handlers (Fn(&Request) -> Response)
impl<F> Handler for F
where
    F: Fn(&Request) -> Response + Send + Sync + 'static,
{
    fn call(
        &self,
        req: &Request,
    ) -> Pin<Box<dyn Future<Output = Response> + Send + '_>> {
        let res = (self)(req);
        // Wrap the sync result in an async block – the future does not borrow anything.
        Box::pin(async move { res })
    }
}

// Implementation for asynchronous handlers (Fn(&Request) -> impl Future)
impl<F, Fut> Handler for F
where
    F: Fn(&Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send,
{
    fn call(
        &self,
        req: &Request,
    ) -> Pin<Box<dyn Future<Output = Response> + Send + '_>> {
