    /// Simple synchronous convenience to handle a request (blocks on the underlying future).
    pub fn handle(&self, path: &str, req: Request) -> Response {
        let handler = self
            .routes
            .get(path)
            .expect("Route not found");
        // The handler returns a future – we block on it.
        block_on(handler.call(&req))
    }
}

// ---------------------------------------------------------------------------
// Example user code – the API that the user wants
// ---------------------------------------------------------------------------
fn sync_handler(req: &Request) -> Response {
    Response::new(format!("sync response: {}", req.0))
}

async fn async_handler(req: &Request) -> Response {
    Response::new(format!("async response: {}", req.0))
}

fn main() {
    let mut server = Server::new();

    // The same call works for both sync and async handlers
    server.add_route("/sync", sync_handler);
    server.add_route("/async", async_handler);

    let request = Request("Hello".to_string());

    let resp_sync = server.handle("/sync", request.clone());
    println!("{}", resp_sync.0);

    let resp_async = server.handle("/async", request);
    println!("{}", resp_async.0);
}
