mod al {
    /// The abstract `Rest` trait that defines the network service interface.
    pub trait Rest {
        fn name(&self) -> String;
        fn do_something(&self, value: i32) -> i32;
    }
}

mod il {
    use crate::al::Rest;

    /// First concrete implementation of `Rest`.
    pub struct Foo {
        pub x: i32,
    }

    impl Rest for Foo {
        fn name(&self) -> String {
            format!("Foo({})", self.x)
        }

        fn do_something(&self, value: i32) -> i32 {
            self.x + value
        }
    }

    /// Second concrete implementation of `Rest`.
    pub struct Boo {
        pub y: i32,
    }

    impl Rest for Boo {
        fn name(&self) -> String {
            format!("Boo({})", self.y)
        }

        fn do_something(&self, value: i32) -> i32 {
            self.y * value
        }
    }
}

mod bl {
    // Bring the trait into scope – the `enum_dispatch` macro will use it.
    use crate::al::Rest;
    use crate::il::{Foo, Boo};

    /// The business‑layer enum that aggregates the different implementations.
    /// `#[enum_dispatch]` generates a static dispatch implementation of `Rest`
    /// for this enum, allowing direct method calls on the enum variants with
    /// zero runtime overhead.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }
}

fn main() {
    // Example usage of the static‑dispatch enum.
    let a = bl::Item::Foo(il::Foo { x: 42 });
    let b = bl::Item::Boo(il::Boo { y: 5 });

    // Calls are resolved at compile time, just like dynamic dispatch
    // but without any virtual call overhead.
    println!("a.name() = {}", a.name());
