fn main() -> io::Result<()> {
    println!("Starting event loop. Press 'q' to quit.");
    println!("The 'tick' message should now appear every second,");
    println!("regardless of whether you press keys or not.\n");

    let tick_rate = Duration::from_secs(1);
    let mut last_tick = Instant::now();

    loop {
        // Calculate the time remaining until the next tick.
        // If the time has passed, we use a timeout of 0 to avoid sleeping.
        let time_until_next_tick = tick_rate.saturating_sub(last_tick.elapsed());

        // Poll for input events.
        // 'poll' will block until either:
        // 1. An input event occurs (keypress, resize, etc.), OR
        // 2. The calculated 'time_until_next_tick' duration passes.
        //
        // This is the key to solving the blocking issue.
        let event_available = event::poll(time_until_next_tick)
            .map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;

        // If an event occurred, handle it.
        // Since poll returned true, this read() is non-blocking.
        if event_available {
            match event::read().map_err(|e| io::Error::new(io::ErrorKind::Other, e))? {
                Event::Key(key) => {
                    if key.code == KeyCode::Char('q') {
                        println!("'q' pressed, quitting.");
                        break;
