        // We check this on every loop iteration:
        // - If poll timed out, we definitely crossed the tick threshold.
        // - If we received input, we might have crossed the threshold while handling input.
        if last_tick.elapsed() >= tick_rate {
            println!("Tick! (Time to redraw UI)");

            // Flush stdout to ensure the message appears immediately in the terminal
            io::stdout().flush()?;

            // Reset the timer.
            // Using Instant::now() is simple. For more precise timing,
            // you could add tick_rate to last_tick, but this is standard for simple TUI apps.
