use tokio::sync::oneshot;
use tokio::time::{sleep, Duration};

/// Queue handler that processes work until it receives a stop signal.
async fn run_queue(stop_rx: oneshot::Receiver<()>) {
    loop {
        tokio::select! {
            // Stop signal received
            _ = stop_rx => {
                info!("Queue handler: stop signal received, shutting down.");
                break;
            }
            // Simulate periodic work
            _ = sleep(Duration::from_secs(1)) => {
                info!("Queue handler: processing a tick...");
            }
        }
    }
    info!("Queue handler: finished.");
}

#[actix_web::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Initialise logging (env_logger)
    env_logger::init();

    info!("Starting the application");

    // Build the Actix Web server.
    // We disable the default signal handling so we can handle Ctrl+C ourselves.
    let server = HttpServer::new(|| {
        App::new()
            .route("/", web::get().to(|| async { HttpResponse::Ok().body("Hello from Actix Web!") }))
    })
    .disable_signals()
    .bind("127.0.0.1:8080")?;

    // We need a second handle to stop the server later.
    let server_handle = server.clone();

    // Create a channel to signal the queue handler to stop.
    let (queue_stop_tx, queue_stop_rx) = oneshot::channel();

    // Spawn the queue handler.
    let queue_task = tokio::spawn(run_queue(queue_stop_rx));

    // Spawn the Actix Web server.
    let server_task = tokio::spawn(async move {
        if let Err(e) = server.run().await {
            error!("Server error: {}", e);
        }
    });

    // Wait for Ctrl+C.
    info!("Waiting for Ctrl+C...");
    ctrl_c().await?;
    info!("Ctrl+C received, initiating graceful shutdown...");

    // Stop the Actix Web server (graceful shutdown).
    server_handle.stop(true).await;
    info!("Server stopped");

    // Tell the queue handler to stop.
    let _ = queue_stop_tx.send(());
    info!("Queue stop signal sent");

    // Wait for both background tasks to finish.
    let _ = tokio::join!(server_task, queue_task);
    info!("All tasks finished, exiting");

    Ok(())
}
