use std::fs;
use std::fmt;
use std::path::PathBuf;

use serde::de::{self, Deserialize, Deserializer, Visitor};
use serde::Deserialize;
use serde_json::{self, Value, from_str, from_value};

struct PathListVisitor;

impl<'de> Visitor<'de> for PathListVisitor {
    type Value = Vec<PathBuf>;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a sequence of pathbufs or a $ref object")
    }

    fn visit_seq<A>(self, mut seq: A) -> Result<Self::Value, A::Error>
    where
        A: de::SeqAccess<'de>,
    {
        let mut vec = Vec::new();
        while let Some(elem) = seq.next_element::<String>()? {
            vec.push(PathBuf::from(elem));
        }
        Ok(vec)
    }

    fn visit_map<A>(self, mut map: A) -> Result<Self::Value, A::Error>
    where
        A: de::MapAccess<'de>,
    {
        // Expecting a map with "$ref" key
        let mut ref_key = None;
        while let Some(key) = map.next_key::<String>()? {
            if key == "$ref" {
                ref_key = Some(map.next_value::<String>()?);
            } else {
                // Ignore other keys
                let _: Value = map.next_value()?;
            }
        }
        let ref_str = ref_key.ok_or_else(|| de::Error::custom("missing $ref"))?;
        // Resolve reference
        // The reference format: "./a.json#/p_list"
        // We need to parse the file path and the JSON pointer.
        let (file_path, pointer) = match ref_str.split_once('#') {
            Some((fp, ptr)) => (fp, if ptr.is_empty() { None } else { Some(ptr) }),
            None => (ref_str.as_str(), None),
        };

        // Resolve relative path based on current working directory.
        let base_dir = env::current_dir().unwrap_or_default();
        let absolute_path = base_dir.join(file_path);
        let json_str = fs::read_to_string(&absolute_path).map_err(|e| de::Error::custom(format!("failed to read referenced file: {}", e)))?;
        let json_value: Value = from_str(&json_str).map_err(|e| de::Error::custom(format!("failed to parse referenced JSON: {}", e)))?;

        // Resolve JSON pointer
        let target = if let Some(ptr) = pointer {
            // parse pointer: split by '/' and navigate
            let parts = ptr.trim_start_matches('/').split('/');
            let mut current = json_value;
            for part in parts {
                if let Value::Object(map) = &current {
                    // part may be a string key
                    if let Some(v) = map.get(part) {
                        current = v;
                    } else {
                        return Err(de::Error::custom(format!("pointer not found: {}", part)));
                    }
                } else {
                    return Err(de::Error::custom("invalid pointer: not an object"));
                }
            }
            current
        } else {
            json_value
        };

        // Now deserialize the target to Vec<PathBuf>
        let path_list: Vec<PathBuf> = from_value(target.clone()).map_err(|e| de::Error::custom(format!("failed to deserialize path list: {}", e)))?;
        Ok(path_list)
    }
}

impl<'de> Deserialize<'de> for Vec<PathBuf> {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_any(PathListVisitor)
    }
}

