    // Check if it's signedData (OID 1.2.840.113549.1.7.2)
    if ci.content_type.as_bytes() != b"1.2.840.113549.1.7.2" {
        eprintln!("Not a SignedData content type");
        std::process::exit(1);
    }

    // Get the raw content bytes from the ContentInfo
    // This bypasses potential issues with explicit tag handling
    let content_bytes = ci.content.as_bytes();
    println!("Content length: {} bytes", content_bytes.len());

    // Try to decode the content as SignedData directly from the raw bytes
    let sd = match SignedData::from_der(content_bytes) {
        Ok(sd) => sd,
        Err(e) => {
            eprintln!("Failed to decode SignedData: {:?}", e);
            // Print first 200 bytes as hex for debugging
