```json
{
  "Cargo.toml": "[package]
name = "parallel_neighbor"
version = "0.1.0"
edition = "2021"

[dependencies]
rayon = "1.5"
",
  "main.rs": "use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn new(r: Vec<f64>) -> Self {
        B {
            r,
            v: Vec::new(),
            f: Vec::new(),
            nb: Vec::new(),
        }
    }

    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn new(cutoff: f64) -> Self {
        A {
            elems: Vec::new(),
            cutoff,
        }
    }

    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    pub fn push(&mut self, elem: B) {
        self.elems.push(elem);
    }

    /// Sequential solution without unsafe pointers.
    /// Uses indices instead of raw pointers.
    /// Modifies both elements when criterion is met.
    pub fn build_lists_sequential(&mut self) {
        let nelems = self.elems.len();

        for i in 0..nelems {
            self.elems[i].nb.clear();

            // Iterate over following elements only (j > i) to avoid duplicates
            for j in (i + 1)..nelems {
                if self.elems[i].criterion(&self.elems[j]) < self.cutoff {
                    // Modify both elements
                    self.elems[i].nb.push(j);
                    self.elems[j].nb.push(i);
                }
            }
        }
    }

    /// Parallel solution using rayon.
    /// Uses a two-phase approach:
    /// 1. Find all pairs in parallel (read-only)
    /// 2. Apply modifications sequentially
    pub fn build_lists_parallel(&mut self) {
        let nelems = self.elems.len();

        // Immutable borrow for reading phase
        let elems = &self.elems;
        let cutoff = self.cutoff;

        // Phase 1: Find all pairs in parallel (read-only)
        let pairs: Vec<(usize, usize)> = (0..nelems)
            .into_par_iter()
            .flat_map(|i| {
                let mut local_pairs = Vec::new();
                let elem_i = &elems[i];
                for j in (i + 1)..nelems {
                    if elem_i.criterion(&elems[j]) < cutoff {
                        local_pairs.push((i, j));
                    }
                }
                local_pairs
            })
            .collect();

        // Phase 2: Apply modifications sequentially
        // (Cannot easily parallelize due to potential conflicts in nb vectors)
        for (i, j) in pairs {
            self.elems[i].nb.push(j);
            self.elems[j].nb.push(i);
        }
    }
}

fn main() {
    // Create test data: 100 particles in a line
    let cutoff = 1.0;
    let mut a = A::new(cutoff);

    for i in 0..100 {
        let x = (i as f64) * 0.1;
        a.push(B::new(vec![x, 0.0, 0.0]));
    }

    println!("Number of elements: {}", a.get_nelems());

    // Sequential version
    let mut a_seq = a.clone();
    a_seq.build_lists_sequential();
    println!("Sequential: elems[0].nb = {:?}", a_seq.elems[0].nb);
    println!("Sequential: elems[5].nb = {:?}", a_seq.elems[5].nb);

    // Parallel version
    let mut a_par = a.clone();
    a_par.build_lists_parallel();
    println!("Parallel: elems[0].nb = {:?}", a_par.elems[0].nb);
    println!("Parallel: elems[5].nb = {:?}", a_par.elems[5].nb);

    // Verify results match
    for i in 0..a.elems.len() {
        assert_eq!(
            a_seq.elems[i].nb,
            a_par.elems[i].nb,
            "Mismatch at index {}",
            i
        );
    }
    println!("Success: Sequential and Parallel results match!");
}
"
}
```

