Here is a complete, self-contained solution using Dioxus. It implements a custom event system using a Context that holds a list of `EventHandler` callbacks, allowing child components to "subscribe" to global drag events without causing the entire component tree to re-render unnecessarily.

```json
{
  "Cargo.toml": "[package]
name = "dioxus-drag"
version = "0.1.0"
edition = "2021"

[dependencies]
dioxus = "0.7"
dioxus-log = "0.7"
log = "0.4"

[profile.release]
opt-level = "z"
",
  "main.rs": "use dioxus::prelude::*;
use dioxus_log::tracing;

// Define the custom event type
#[derive(Clone, Copy)]
struct DragEvent {
    x: i32,
    y: i32,
}

// The Context struct to manage global drag events
// It holds a list of callbacks (EventHandlers) that are called when drag events occur.
#[derive(Clone)]
struct DragContext {
    listeners: Signal<Vec<EventHandler<DragEvent>>>,
    is_dragging: Signal<bool>,
}

impl DragContext {
    fn new() -> Self {
        Self {
            listeners: use_signal(Vec::new),
            is_dragging: use_signal(|| false),
        }
    }

    // Allow children to subscribe to drag events
    fn subscribe(&self, handler: EventHandler<DragEvent>) {
        self.listeners.write().push(handler);
    }
}

// The Provider component that wraps the SVG area
#[component]
fn DragProvider(children: Element) -> Element {
    let ctx = use_context_provider(DragContext::new);

    // Handle global mouse events to drive the custom event system
    let onmousemove = move |e: MouseEvent| {
        if *ctx.is_dragging.read() {
            let coords = e.element_coordinates();
            let drag_evt = DragEvent {
                x: coords.x as i32,
                y: coords.y as i32,
            };

            // Dispatch the custom event to all subscribed listeners
            // Note: We iterate over a clone or read to avoid borrow issues,
            // but since we are inside an event handler, we can safely read.
            for handler in ctx.listeners.read().iter() {
                handler.call(drag_evt);
            }
        }
    };

    let onmousedown = move |_| {
        ctx.is_dragging.set(true);
    };

    let onmouseup = move |_| {
        ctx.is_dragging.set(false);
    };

    rsx! {
        div {
            width: "100%",
            height: "100vh",
            onmousedown: onmousedown,
            onmouseup: onmouseup,
            onmousemove: onmousemove,
            // We use a sub-container to ensure the SVG takes focus or specific area
            svg {
                width: "100%",
                height: "100%",
                background: "#f0f0f0",
                {children}
            }
        }
    }
}

// The Draggable Point Component
#[component]
fn Point(x: i32, y: i32) -> Element {
    let mut position = use_signal(|| (x, y));
    let ctx = use_context::<DragContext>();

    // We use a local signal to track if THIS specific point is being dragged.
    // Although the global provider tracks "is dragging" in general,
    // we might want per-element state or simply rely on the event handler logic.
    let mut is_local_dragged = use_signal(|| false);

    // Subscribe to the global drag events
    // We use use_effect to register the callback once on mount.
    use_effect(move || {
        let handler = EventHandler::new(move |evt: DragEvent| {
            // Only update if this specific point initiated the drag
            // For simplicity in this demo, we check the global drag state.
            // In a more complex app, you might check an ID.
            if *is_local_dragged.read() {
                position.set((evt.x, evt.y));
            }
        });
        ctx.subscribe(handler);
    });

    rsx! {
        circle {
            cx: "{position.read().0}",
            cy: "{position.read().1}",
            r: 10,
            fill: "red",
            cursor: "pointer",

            // Start dragging
            onmousedown: move |e| {
                e.stop_propagation();
                is_local_dragged.set(true);
                // Also tell the global provider we started (though provider catches this on bg)
                ctx.is_dragging.set(true);
            },

            // Stop dragging
            onmouseup: move |_| {
                is_local_dragged.set(false);
                ctx.is_dragging.set(false);
            }
        }
    }
}

#[component]
fn App() -> Element {
    rsx! {
        DragProvider {
            svg {
                // Render a few draggable points
                Point { x: 100, y: 100 }
                Point { x: 200, y: 150 }
                Point { x: 300, y: 100 }
            }
        }
    }
}

fn main() {
    dioxus::launch::launch(App);
}
"
}
```

