  "main.rs": "use std::io::{Read, Write};
use std::sync::mpsc;
use std::thread;

use portable_pty::{native_pty_system, CommandBuilder, PtySize};
use rustyline::completion::{Completer, Pair};
use rustyline::{Editor, Helper};
use rustyline::error::ReadlineError;

struct ReplHelper {
    commands: Vec<String>,
}

impl ReplHelper {
    fn new() -> Self {
        let commands = vec![
            "help".to_string(),
            "quit".to_string(),
            "echo".to_string(),
            "date".to_string(),
            "ls".to_string(),
        ];
        Self { commands }
    }
}

impl Completer for ReplHelper {
    fn complete(&self, line: &str, _pos: usize) -> Vec<Pair> {
        self.commands
            .iter()
            .filter(|c| c.starts_with(line))
            .map(|c| Pair {
                display: c.clone(),
                replacement: c.clone(),
            })
            .collect()
    }
}

impl Helper for ReplHelper {}

fn main() -> std::io::Result<()> {
    // Create a PTY pair
    let pty_system = native_pty_system();
    let pair = pty_system.openpty(PtySize {
        rows: 24,
        cols: 80,
        pixel_width: 0,
        pixel_height: 0,
    })?;

    let master = pair.master;
    let slave = pair.slave;

    // Spawn a child REPL (bash -i as an example)
    let mut cmd = CommandBuilder::new("bash");
    cmd.arg("-i");
    let mut child = slave.spawn_command(cmd)?;

    // Take the reader and writer for the master side
    let mut master_reader = master.take_reader()?;
    let mut master_writer = master.take_writer()?;

    // Channel to forward child output to the main thread
    let (output_tx, output_rx) = mpsc::channel();

    // Spawn a thread that reads the child's output and sends it to the main thread
    thread::spawn(move || {
        let mut buf = [0u8; 1024];
        loop {
            match master_reader.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    let s = String::from_utf8_lossy(&buf[..n]).to_string();
                    if output_tx.send(s).is_err() {
                        // Main thread has dropped the sender, exit
                        break;
                    }
                }
                Err(e) => {
                    eprintln!("Error reading from child: {}", e);
                    break;
                }
            }
        }
    });

    // Set up rustyline with our custom completer
    let helper = ReplHelper::new();
    let mut rl = Editor::new();
    rl.set_helper(Some(helper));

    // Main event loop
    loop {
        // Drain any pending output from the child
        while let Ok(output) = output_rx.try_recv() {
            print!("{}", output);
            std::io::stdout().flush().unwrap();
            // Redraw the input line so the user sees what they are typing
            let _ = rl.refresh_line();
        }

        // Read a line from the user
        match rl.readline("> ") {
            Ok(line) => {
                // Add the line to history
                rl.add_history_entry(&line);
                // Send the line to the child REPL
                let line = line.trim_end_matches('\n');
                master_writer.write_all(line.as_bytes()).unwrap();
                master_writer.write_all(b"\n").unwrap();
                master_writer.flush().unwrap();
            }
            Err(ReadlineError::Eof) => {
                println!("EOF");
                break;
            }
            Err(e) => {
                eprintln!("Error: {:?}", e);
                break;
            }
        }
    }

    // Clean up: kill the child process
    let _ = child.kill();

    Ok(())
}
"
