use serde_json::Value;
use std::fs;
use std::path::PathBuf;

// Helper function to resolve a JSON Pointer (RFC 6901)
fn resolve_json_pointer(value: &Value, pointer: &str) -> Option<Value> {
    // Empty pointer points to the root
    if pointer.is_empty() {
        return Some(value.clone());
    }
    // Pointer must start with '/'
    if !pointer.starts_with('/') {
        return None;
    }

    let mut current = value.clone();
    // Skip the leading '/' and split by remaining '/'
    for key in pointer[1..].split('/') {
        // Unescape JSON Pointer special characters: ~1 -> /, ~0 -> ~
        let key = key.replace("~1", "/").replace("~0", "~");
        match current {
            Value::Object(map) => {
                current = map.get(&key)?.clone();
            }
            _ => return None,
        }
    }
    Some(current)
}

// Custom deserializer function to handle either a direct list or a $ref object
fn deserialize_path_list<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    // 1. Deserialize the field into a generic JSON Value
    let val = Value::deserialize(deserializer)?;

    match val {
        // Case A: Direct array ["path1", "path2"]
        Value::Array(arr) => {
            serde_json::from_value(Value::Array(arr)).map_err(serde::de::Error::custom)
        }
        // Case B: Object with $ref {"$ref": "..."}
        Value::Object(map) => {
            if let Some(Value::String(ref_path)) = map.get("$ref") {
                // Parse the reference string (e.g., "./a.json#/p_list")
                let parts: Vec<&str> = ref_path.splitn(2, '#').collect();
                let file_path = parts.first().unwrap();
                let pointer = parts.get(1).map(|s| *s).unwrap_or("");

                // Read the referenced file (relative to the current working directory)
                let content = fs::read_to_string(file_path)
                    .map_err(|e| serde::de::Error::custom(format!("Failed to read file '{}': {}", file_path, e)))?;

                // Parse the file content as JSON
                let json: Value = serde_json::from_str(&content)
                    .map_err(|e| serde::de::Error::custom(format!("Failed to parse JSON from '{}': {}", file_path, e)))?;

                // Extract the specific value using the JSON pointer
                let target = resolve_json_pointer(&json, pointer)
                    .ok_or_else(|| serde::de::Error::custom("Invalid JSON pointer or target not found"))?;

                // Deserialize the extracted value into Vec<PathBuf>
                serde_json::from_value(target).map_err(serde::de::Error::custom)
            } else {
                Err(serde::de::Error::custom("Expected object with '$ref' key"))
            }
        }
        _ => Err(serde::de::Error::custom("Expected array or object with $ref")),
    }
}

#[derive(Deserialize, Debug)]
struct A {
    #[serde(deserialize_with = "deserialize_path_list")]
    path_list: Vec<PathBuf>,
}

fn main() {
    // Read the file containing references
    let json_data = fs::read_to_string("b.json").expect("failed to read from b.json");

    // Deserialize using our custom logic
    let a_obj: A = serde_json::from_str(&json_data).expect("deserialization failed");

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }
}
"
}
