// The stream type - note the lifetime order: input lifetime first, then state lifetime
struct SStream<'i, 'e> {
    input: &'i str,
    // In real code this would be the actual state
    _state: &'e (),
}

// A simple parser trait similar to ModalParser
trait Parser<'i, 'e, Output> {
    fn parse(&mut self, input: SStream<'i, 'e>) -> Result<Output, ()>;
}

// Example parser implementation
struct ConsParser;

impl<'e> Parser<'_, 'e, &'e str> for ConsParser {
    fn parse(&mut self, mut input: SStream<'_, 'e>) -> Result<&'e str, ()> {
        // Just return the input for demonstration
        Ok(input.input)
    }
}

// THE PROBLEMATIC TEST HELPER - as written in the question
// This won't compile because POut's lifetime isn't connected to 'e
pub fn test_input_output_problematic<'i, ExOut, POut, P>(
    _input: &'i str,
    _expected_output: &ExOut,
    _parser: P,
) where
    POut: PartialEq<ExOut> + Debug,
    ExOut: Debug,
    for<'e> P: Parser<SStream<'e, 'i>, POut, ()>,
{
    // The 'e lifetime here is introduced by the for<'e> bound
    // but there's no way to constrain POut to have the same 'e lifetime
    // This is the core issue!
}

// THE SOLUTION: Don't use 'e in the trait bound
// Instead, let the caller specify the parser with concrete lifetimes
// and the test function creates the stream with those lifetimes

pub fn test_input_output<'i, ExOut, POut, P>(
    input: &'i str,
    expected_output: &ExOut,
    parser: P,
) where
    POut: PartialEq<ExOut> + Debug,
    ExOut: Debug,
    P: for<'e> Parser<SStream<'_, 'e>, POut, ()>,
{
    // Create the state with the 'e lifetime from inside the function
    let state = ();

    // This works because we're creating SStream with the lifetime 'e
    // that exists inside this function's scope
    let stream = SStream {
        input,
        _state: &state,
    };

    // Note: In the actual code, the issue is that the parser's output type
    // needs to be valid for the same lifetime as the state we create.
    // The for<'e> bound allows the parser to work with ANY 'e, which is correct.

    println!("Testing: {:?}", expected_output);
}

// Alternative approach: Use a closure to capture the relationship
pub fn test_input_output_closure<'i, ExOut, POut, F>(
    input: &'i str,
    expected_output: &ExOut,
    parse_fn: F,
) where
    POut: PartialEq<ExOut> + Debug,
    ExOut: Debug,
    F: for<'e> FnMut(SStream<'_, 'e>) -> Result<POut, ()>,
{
    let state = ();
    let stream = SStream {
        input,
        _state: &state,
    };

    let parsed = match parse_fn(stream) {
        Ok(p) => p,
        Err(_) => panic!("parse failed"),
    };

    assert_eq!(&parsed, expected_output);
}

fn main() {
