#[derive(Debug)]
enum Message {
    Key(Event),
    Signal(i32),
    Quit,
}

fn spawn_signal_thread(tx: Sender<Message>, stop: Arc<AtomicBool>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();
        for sig in signals.forever() {
            if stop.load(Ordering::Relaxed) {
                break;
            }
            let _ = tx.send(Message::Signal(sig));
        }
    })
}

fn spawn_key_thread(tx: Sender<Message>, stop: Arc<AtomicBool>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        let stdin = std::io::stdin();
        let mut stdin = stdin.lock();
