/// Recursively enumerate all files and directories under `path`.
async fn list_dir_recursive(tree: &Tree, path: &str) -> Result<(), Box<dyn std::error::Error>> {
    // Open the path as a directory (or file) with read‑directory access.
    let resource = tree
        .open_existing(path, FileAccessMask::FILE_LIST_DIRECTORY)
