pub trait Scalar: PartialEq {}
impl Scalar for bool {}
impl Scalar for i32 {}
impl Scalar for &str {}
impl Scalar for String {}
impl Scalar for Stress {}
impl Scalar for Gender {}

pub trait PartialMatch {
    fn matches(&self, filter: &Self) -> bool;
}

impl<T: Scalar> PartialMatch for T {
    fn matches(&self, filter: &T) -> bool { self == filter }
}

impl<T: PartialMatch> PartialMatch for Option<T> {
    fn matches(&self, filter: &Option<T>) -> bool {
        match (self, filter) {
            (_, None) => true,
            (Some(s), Some(f)) => s.matches(f),
            (None, Some(_)) => false,
        }
    }
}

macro_rules! impl_partial_match {
    ($struct:ident { $($field:ident),* $(,)? }) => {
        impl PartialMatch for $struct {
            fn matches(&self, filter: &$struct) -> bool {
                true
                $(
                    && self.$field.matches(&filter.$field)
                )*
            }
        }
    };
