  "main.rs": "use clap::{Args, Parser, Subcommand};

/// CLI application for node management
#[derive(Parser)]
#[command(name = "cli")]
#[command(about = "A CLI for node operations", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Node operations
    Node(NodeCommand),
}

/// Node operations
/// 
/// Supports three command patterns:
/// - `node create <NAME>` - create a new node
/// - `node get <NAME>` - get node information
/// - `node <NAME> link <TARGET>` - link node to target
#[derive(Subcommand)]
enum NodeCommand {
    /// Create a new node
    /// 
    /// Usage: cli node create <NAME>
    Create {
        /// Name of the node to create
        name: String,
    },

    /// Get node information
    /// 
    /// Usage: cli node get <NAME>
    Get {
        /// Name of the node to get
        name: String,
    },

    /// Link this node to a target
    /// 
    /// Usage: cli node <NAME> link <TARGET>
    Link {
        /// Name of the node
        #[arg(last = true)]
        name: String,

        /// The link subcommand (required)
        #[command(subcommand)]
        action: LinkAction,
    },
}

#[derive(Subcommand)]
enum LinkAction {
    /// Link this node to a target
    Target {
        /// Target to link to
        target: String,
    },
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Commands::Node(NodeCommand::Create { name }) => {
            println!("Creating node: {}", name);
        }
        Commands::Node(NodeCommand::Get { name }) => {
            println!("Getting node: {}", name);
        }
        Commands::Node(NodeCommand::Link { name, action }) => {
            let target = match action {
                LinkAction::Target { target } => target,
            };
            println!("Linking node '{}' to target '{}'", name, target);
        }
    }
}
"
}
