  "main.rs": "use std::env;
use std::fs;
use ra_ap_syntax::{Syntax, ast::{Use, UseTree, UseTreeList}};

fn transform_use_tree(tree: &UseTree, prefix: &str) -> String {
    let path_opt = tree.path();
    let star_opt = tree.star();
    let list_opt = tree.use_tree_list();

    let path_str = path_opt.as_ref().map(|p| p.to_string()).unwrap_or_default();

    // Determine the full path for this node
    let full_path = if prefix.is_empty() {
        path_str.clone()
    } else if path_str.is_empty() {
        prefix.to_string()
    } else {
        format!("{}::{}", prefix, path_str)
    };

    // Transform full path if it starts with the target prefix
    let transformed_full_path = if full_path.starts_with("vexide::devices") {
        full_path.replace("vexide::devices", "vexide")
    } else {
        full_path.clone()
    };

    // Compute the new segment relative to the current prefix
    let new_seg = if prefix.is_empty() {
        transformed_full_path.clone()
    } else {
        let prefix_with_sep = format!("{}::", prefix);
        transformed_full_path.strip_prefix(&prefix_with_sep)
            .map(|s| s.to_string())
            .unwrap_or(transformed_full_path.clone())
    };

    // Build the string for this node
    let mut result = new_seg;

    // Handle wildcard
    if star_opt.is_some() {
        if !result.is_empty() {
            result.push_str("::*");
        } else {
            result.push('*');
        }
    }

    // Process children, if any
    if let Some(list) = list_opt {
        let child_prefix = transformed_full_path.clone();
        let child_strings: Vec<String> = list.use_trees()
            .map(|child| transform_use_tree(&child, &child_prefix))
            .filter(|s| !s.is_empty())
            .collect();

        if !child_strings.is_empty() {
            if !result.is_empty() {
                result.push_str(&format!("{{{}}}", child_strings.join(", ")));
            } else {
                // No path, just braces
                result.push_str(&format!("{{{}}}", child_strings.join(", ")));
            }
        }
    }

    // If the node would become empty (no path, no star, no children), drop it
    if result.is_empty() && star_opt.is_none() {
        return String::new();
    }

    result
}

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <file>", args[0]);
        return;
    }
    let file_path = &args[1];
    let source = fs::read_to_string(file_path).expect("Failed to read file");

    let parse = Syntax::parse(&source);
    let mut root = parse.syntax();

    // Process each use statement iteratively
    loop {
        let use_item = root.descendants().filter_map(Use::cast).next();
        match use_item {
            None => break,
            Some(use_item) => {
                if let Some(tree) = use_item.use_tree() {
                    let transformed = transform_use_tree(&tree, "");
                    let new_stmt = format!("use {};", transformed);
                    let new_parse = Syntax::parse(&new_stmt);
                    let new_use = new_parse.syntax()
                        .descendants()
                        .find_map(Use::cast)
                        .expect("Failed to parse transformed use statement");
                    let new_tree = new_use.use_tree()
                        .expect("Failed to get use tree from transformed statement");
                    root = root.replace(tree.syntax(), new_tree.syntax());
                }
            }
        }
    }

    let output = root.to_string();
    fs::write(file_path, output).expect("Failed to write file");
    println!("Imports rewritten in {}", file_path);
}
"
