use bevy::prelude::*;
use bytes::Bytes;
use std::path::PathBuf;
use zip::ZipArchive;

// Define a custom asset reader that reads from a zip container.
// The assets are loaded lazily: each asset is only read when requested.
struct ZipAssetReader {
    // The root path where the container files are located.
    root: PathBuf,
}

impl ZipAssetReader {
    fn new(root: PathBuf) -> Self {
        Self { root }
    }
}

// Implement the AssetReader trait for our custom reader.
// This allows Bevy to use our reader for assets loaded from the custom source.
impl bevy::asset::AssetReader for ZipAssetReader {
    type Error = anyhow::Error;

    fn read(&self, path: &std::path::Path) -> Result<Bytes, Self::Error> {
        // The path is relative to the source root (the container file).
        // We need to extract the container name and the entry name.
        // Expected format: "container_name.zip/entry_name".
        let path_str = path.to_string_lossy();
        let (container, entry) = path_str
            .split_once('/')
            .context("Invalid path format: expected 'container.zip/entry'")?;


        // Open the container file (zip) from the root.
        let container_path = self.root.join(container);
        let file = std::fs::File::open(&container_path)
            .with_context(|| format!("Failed to open container: {:?}", container_path))?;

        let mut archive = ZipArchive::new(file)
            .with_context(|| format!("Failed to read zip archive: {:?}", container_path)?;

        // Get the entry from the archive.
        let mut zip_entry = archive
            .by_name(entry)
            .with_context(|| format!("Entry '{}' not found in container", entry))?;

        // Read the entry's contents.
        let mut buffer = Vec::new();
        zip_entry
            .read_to_end(&mut buffer)
            .with_context(|| format!("Failed to read entry '{}'", entry))?;


        Ok(Bytes::from(buffer))
    }


    // We don't need to implement read_meta for this example.
    fn read_meta(&self, _path: &std::path::Path) -> Result<bevy::asset::Metadata, Self::Error> {
        // Return default metadata.
        Ok(bevy::asset::Metadata::new(bevy::asset::AssetMetadataKind::File))
    }
}


fn main() {
    // Initialize logger.
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();
    log::info!("Starting lazy loader example");


    // Create the app.
    let mut app = App::new();

    // Add default plugins (MinimalPluginGroup includes DefaultPlugins).
    app.add_plugins(DefaultPlugins);


    // Get the assets folder path.
    let assets_folder = app.world().resource::<bevy::asset::AssetServer>().asset_dir();
