use tracing::{info, info_span, Span};
use tracing_futures::Instrument;

// -------------------------------------------------------------------
// 1.  A simple request context that holds the parent span.
// -------------------------------------------------------------------
#[derive(Clone)]
struct RequestContext {
    /// The top‑level span that represents the whole request.
    parent: Span,
}

impl RequestContext {
    /// Create a new context and start the request span.
    fn new() -> Self {
        // The request span will be the root of the whole pipeline.
        let parent = info_span!("request");
        Self { parent }
    }

    /// Run the whole pipeline inside the request span.
    ///
    /// Because each stage function expects a parent span, we pass the
    /// request span to the first stage.  The `in_scope` call makes the
    /// request span current for the duration of the passed future, which
    /// guarantees that any span created inside it will be a child of the
    /// request span.
    async fn run_pipeline(&self) {
        // Re‑hydrate the request span for this async context.
        self.parent.clone().in_scope(async {
            info!("Starting request pipeline");
            // Stage 1 is given the request span as its parent.
            stage1(self.parent.clone()).await;
            info!("Request pipeline completed");
        }).await;
    }
}

// -------------------------------------------------------------------
// 2.  Stage functions that each create a child span.
// -------------------------------------------------------------------

/// Stage 1 – the first processing step.
async fn stage1(parent: Span) {
    // Create a child span whose parent is the passed-in span.
    let span = info_span!(parent: parent, "stage1");

    // `in_scope` makes the span current for the duration of the future.
    span.in_scope(async {
        info!("Stage 1 started");
        tokio::time::sleep(Duration::from_millis(50)).await;

        // Stage 2 is a child of Stage 1.
        stage2(span).await;

        info!("Stage 1 finished");
    }).await;
}

/// Stage 2 – the second processing step.
async fn stage2(parent: Span) {
    let span = info_span!(parent: parent, "stage2");
    span.in_scope(async {
        info!("Stage 2 started");
        tokio::time::sleep(Duration::from_millis(50)).await;

        // The upstream call is a child of Stage 2.
        upstream(span).await;

        info!("Stage 2 finished");
    }).await;
}

/// Upstream – e.g. a call to a backend service.
async fn upstream(parent: Span) {
    let span = info_span!(parent: parent, "upstream");
    span.in_scope(async {
        info!("Upstream call started");
        tokio::time::sleep(Duration::from_millis(50)).await;
        info!("Upstream call finished");
    }).await;
}

// -------------------------------------------------------------------
// 3.  Application entry point.
// -------------------------------------------------------------------
#[tokio::main]
async fn main() {
    // Initialise a basic tracing subscriber that prints to stdout.
    // The "env-filter" feature lets you control verbosity via RUST_LOG.
    tracing_subscriber::fmt()
        .with_env_filter("tracing_rehydrate=debug,info")
        .init();

