        let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);
        tracing_subscriber::registry().with(otel_layer).init();
    }

    // -----------------------------------------------------------------
    // 4.  Run the pipeline.
    // -----------------------------------------------------------------
    let ctx = RequestContext::new();
    ctx.run_pipeline().await;

