#[derive(Debug)]
enum FlusterError {
    FailToParseDate,
}

type FlusterResult<T> = Result<T, FlusterError>;

/// Parses a LanceDB‑style ISO timestamp (with optional fractional seconds)
/// into a chrono NaiveDateTime. Tries the format with fractional seconds first,
/// falling back to the format without.
fn parse_naive_date(d: &str) -> FlusterResult<NaiveDateTime> {
    // Format that expects optional fractional seconds (e.g., .409)
    let fmt_with_fraction = "%Y-%m-%dT%H:%M:%S%.f";
    // Format without any fractional part
    let fmt_without_fraction = "%Y-%m-%dT%H:%M:%S";

    if let Ok(dt) = NaiveDateTime::parse_from_str(d, fmt_with_fraction) {
        return Ok(dt);
    }

    NaiveDateTime::parse_from_str(d, fmt_without_fraction)
        .map_err(|e| {
            eprintln!("Date parse error: {:?}", e);
            FlusterError::FailToParseDate
        })
}

/// Convert a LanceDB ISO timestamp string to a Unix timestamp (seconds since epoch).
pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    let naive = parse_naive_date(d)?;
    // Treat the parsed time as UTC (the ISO string has no explicit time zone).
    let datetime: DateTime<Utc> = Utc.from_utc_datetime(&naive);
    Ok(datetime.timestamp())
}

/// Convert a LanceDB ISO timestamp string to a chrono DateTime<Utc>.
pub fn date_string_to_datetime(d: &str) -> FlusterResult<DateTime<Utc>> {
    let naive = parse_naive_date(d)?;
    let datetime: DateTime<Utc> = Utc.from_utc_datetime(&naive);
    Ok(datetime)
}

