  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use std::time::Duration;
use futures::task::noop_waker_ref;

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Try to poll a future once using a no‑op waker.
/// Returns `Ready` if the future completed, otherwise `Pending`.
fn try_poll<X, F: Future<Output = X>>(future: Pin<&mut F>) -> TryPollResult<X> {
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);
    match future.poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    // Example 1: a future that completes without yielding.
    let mut fut1 = async { 42 };
    match try_poll(Pin::new(&mut fut1)) {
        TryPollResult::Ready(v) => {
            println!("Immediate future ready: {}", v);
        }
        TryPollResult::Pending => {
            // This won't happen for a ready future.
            println!("Unexpected pending for fut1");
        }
    }

    // Example 2: a future that yields (i.e., not ready after the first poll).
    let mut fut2 = async {
        tokio::time::sleep(Duration::from_millis(50)).await;
        123
    };

    // Try to poll once.
    let result = try_poll(Pin::new(&mut fut2));
    match result {
        TryPollResult::Ready(v) => {
            // If it happened to be ready, use it.
            println!("Future completed without yielding: {}", v);
        }
        TryPollResult::Pending => {
            // Not ready yet. Spawn a task to continue awaiting the future.
            let handle = tokio::spawn(async move {
                // The future is moved here, and we await it.
                fut2.await
            });
            // Optionally await the handle.
            let value = handle.await.expect("spawned task failed");
            println!("Future completed after spawning: {}", value);
        }
    }

    println!("Done.");
}
"
}
