/// Example context.
#[derive(Debug)]
pub struct Context(pub i32);

/// The type of a boxed async function that takes a context and returns a
/// future that can be sent between threads.
type BoxedAsyncFn = dyn Fn(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send>>
    + Send
    + 'static;

