/// Helper: wraps an async closure (or any FnOnce) into the required `BoxedAsyncFn`.
pub fn wrap_async<F, Fut>(f: F) -> Box<BoxedAsyncFn>
where
    F: FnOnce(&mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    // Use a Mutex to allow taking the FnOnce multiple times (at most once).
    let task = Mutex::new(Some(f));
    Box::new(move |ctx: &mut Context| {
