  "main.rs": "use axum::{
    extract::ConnectInfo,
    handler::Handler,
    http::{header, Method, StatusCode},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use axum_extra::extract::typed_header::TypedHeader;
use headers::Origin;
use std::net::SocketAddr;
use std::sync::Arc;
use tower::ServiceExt;
use tower_http::cors::CorsLayer;

// ============================================================================
// Origin Check Layer
// ============================================================================

/// A layer that checks the Origin header for WebSocket requests.
/// This is applied before the request reaches the handler.
fn check_origin_layer(allowed_origin: &'static str) -> impl tower::Layer<axum::body::Body> + Clone {
    tower::layer::fn_fn(move |req, next| {
        let allowed_origin = allowed_origin.clone();
        async move {
            // Get the Origin header from the request
            let origin = req
                .headers()
                .get(header::ORIGIN)
                .and_then(|v| v.to_str().ok())
                .map(|s| s.trim_end_matches('/'));

            let allowed = allowed_origin.trim_end_matches('/');

            // Check if origin matches (case-sensitive comparison)
            if origin == Some(allowed) {
                // Origin is valid, proceed with the request
                next.oneshot(req).await
            } else {
                // Origin is invalid
                tracing::warn!(
                    "Origin check failed. Got: {:?}, Expected: {}",
                    origin,
                    allowed
                );
                Ok(Response::builder()
                    .status(StatusCode::FORBIDDEN)
                    .body(axum::body::Body::empty())
                    .unwrap())
            }
        }
    })
}

// ============================================================================
// Application State
// ============================================================================

#[derive(Clone)]
struct AppState {
    allowed_origin: &'static str,
}

// ============================================================================
// Handlers
// ============================================================================

/// WebSocket handler that upgrades the connection
async fn ws_handler(
    ws: axum::extract::WebSocketUpgrade,
    ConnectInfo(addr): ConnectInfo<SocketAddr>,
    TypedHeader(origin): TypedHeader<Origin>,
) -> impl IntoResponse {
    tracing::info!("WebSocket connection from {} with Origin: {}", addr, origin.host().unwrap_or("unknown"));

    ws.on_upgrade(move |socket| async move {
        tracing::info!("WebSocket upgraded for {}", addr);
        // Handle the WebSocket connection
        let (mut sender, mut receiver) = socket.split();

        // Echo back any messages received
        while let Some(msg) = receiver.recv().await {
            if let Ok(msg) = msg {
                if sender.send(msg).await.is_err() {
                    break;
                }
            } else {
                break;
            }
        }
        tracing::info!("WebSocket connection closed for {}", addr);
    })
}

/// Regular HTTP handler for testing
async fn health_check() -> impl IntoResponse {
    (StatusCode::OK, "OK")
}

// ============================================================================
// Main
// ============================================================================

#[tokio::main]
async fn main() {
    // Initialize logging
    tracing_subscriber::fmt()
        .with_target(false)
        .with_env_filter(
            tracing_subscriber::EnvFilter::from_default_env()
                .add_directive(tracing::Level::INFO.into()),
        )
        .init();

    // Configuration
    let allowed_origin = "https://www.example.com";

    tracing::info!("Starting server with allowed origin: {}", allowed_origin);

    // Build the router with multiple layers:
    // 1. CORS layer (for regular HTTP responses)
    // 2. Origin check layer (for WebSocket connections)
    // Note: The origin check layer runs BEFORE the WebSocket upgrade,
    // so it can block invalid origins before the connection is established.
    let app = Router::new()
        .route("/health", get(health_check))
        .route("/ws", get(ws_handler))
        .layer(
            CorsLayer::new()
                .allow_origin(allowed_origin.parse().unwrap())
                .allow_methods([Method::GET, Method::POST])
                .allow_headers([header::CONTENT_TYPE]),
        )
        .layer(check_origin_layer(allowed_origin))
        .into_make_service_with_connect_info::<SocketAddr>();

    // Bind the server
    let addr = SocketAddr::from(([0, 0, 0, 0], 3000));
    tracing::info!("Listening on {}", addr);

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}
"
}
