    data: &'a str,
    more_data: &'a str,
}

// Wrapper that owns both the source String and the borrowed parsed data.
// The lifetime 'a ties the references in MyData to the owned String.
struct ParsedData<'a> {
    // The original JSON string - this keeps the memory alive
    source: String,
    // The deserialized data with references into `source`
    parsed: MyData<'a>,
}

impl<'a> ParsedData<'a> {
    /// Parse the JSON string once, creating a self-contained structure
    /// that owns both the data and the source it references.
    fn new(json: String) -> Result<Self, serde_json::Error> {
        // Here we deserialize from a reference to the string.
        // The resulting MyData has lifetime tied to &json, which is tied to json.
        // When we move json into source, the lifetime is preserved in the struct.
        let parsed: MyData<'a> = serde_json::from_str(&json)?;

