{
  "Cargo.toml": "[package]
name = "graceful_shutdown_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
actix-web = "4"
tokio = { version = "1", features = ["full"] }
log = "0.4"
env_logger = "0.10"
",
  "main.rs": "use actix_web::{web, App, HttpResponse, HttpServer};
use tokio::signal;
use tokio::sync::broadcast;
use tokio::time::sleep;
use std::time::Duration;
use log::info;

struct QueueHandler {
    shutdown: broadcast::Receiver<()>,
}

impl QueueHandler {
    fn new(shutdown: broadcast::Receiver<()>) -> Self {
        Self { shutdown }
    }

    async fn run(mut self) {
        loop {
            tokio::select! {
                _ = self.shutdown.recv() => {
                    info!("Queue handler: shutdown signal received");
                    break;
                }
                _ = sleep(Duration::from_secs(1)) => {
                    info!("Queue handler: processing work...");
                }
            }
        }
        info!("Queue handler: exiting gracefully");
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    env_logger::init();

    info!("Starting application...");

    // Create the HTTP server
    let server = HttpServer::new(|| {
        App::new()
            .route("/", web::get().to(|| async { HttpResponse::Ok().body("Hello") }))
    })
    .bind("127.0.0.1:8080")?
    .run();

    // Get a handle for graceful shutdown
    let server_handle = server.handle();

    // Spawn the server in the background
    actix_web::rt::spawn(server);

    // Create a broadcast channel to signal shutdown to background tasks
    let (shutdown_tx, shutdown_rx) = broadcast::channel(1);

    // Spawn the queue handler
    let queue_handler = QueueHandler::new(shutdown_rx);
    let queue_handle = tokio::spawn(queue_handler.run());

    // Wait for Ctrl+C
    signal::ctrl_c().await.expect("Failed to listen for Ctrl+C");
    info!("Received Ctrl+C, shutting down gracefully...");

    // Stop the HTTP server
    server_handle.stop(true).await;
    info!("HTTP server stopped");

    // Signal the queue handler to stop
    let _ = shutdown_tx.send(());

    // Wait for the queue handler to finish
    queue_handle.await.ok();
    info!("Queue handler stopped");

    info!("Application shutdown complete");
    Ok(())
}
"
}

