name = "resource_ref"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "use std::borrow::Cow;
use std::collections::HashMap;
use std::fmt::{Debug, Formatter, Result as FmtResult};
use std::hash::{Hash, Hasher};
use std::marker::PhantomData;

// --- Resource trait and supporting types ---

#[derive(Debug, Clone, Hash, Eq, PartialEq)]
pub struct ResourceMeta {
    pub name: Option<String>,
}

pub trait Resource: 'static {
    type DynamicType: 'static + Default;
    fn group(dt: &Self::DynamicType) -> Cow<'_, str>;
    fn kind(dt: &Self::DynamicType) -> Cow<'_, str>;
    fn meta(&self) -> ResourceMeta;
}

// --- Example implementation ---

/// Simple dynamic type that owns its group and kind strings.
#[derive(Debug, Clone, Default, Hash, Eq, PartialEq)]
pub struct MyType {
    pub group: String,
    pub kind: String,
}

impl MyType {
    pub fn new() -> Self {
        Self {
            group: "my_group".to_string(),
            kind: "my_kind".to_string(),
        }
    }
}

/// Example resource that uses MyType as its dynamic type.
pub struct MyResource {
    meta: ResourceMeta,
}

impl Resource for MyResource {
    type DynamicType = MyType;

    fn group(dt: &Self::DynamicType) -> Cow<'_, str> {
        // Return a borrowed reference to the group's string.
        Cow::Borrowed(dt.group.as_str())
    }

    fn kind(dt: &Self::DynamicType) -> Cow<'_, str> {
        Cow::Borrowed(dt.kind.as_str())
    }

    fn meta(&self) -> ResourceMeta {
        self.meta.clone()
    }
}

// --- The key type that stores references into the owned DynamicType ---

/// A key for a resource that stores its identifying data.
///
/// The `group` and `kind` fields are `Cow`s that borrow from the owned
/// `dynamic_type` field. By creating the struct first and then filling the
/// borrowed fields, we avoid the "returns a value referencing local variable"
/// error.
#[derive(Clone, Eq, PartialEq)]
pub struct ResourceRef<'a, R: Resource>
where
    R::DynamicType: 'a,
    R: Hash,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<Cow<'a, str>>,
    kind: Option<Cow<'a, str>>,
    name: String,
}

// Manual implementation of Debug because of the PhantomData.
impl<'a, R: Resource> Debug for ResourceRef<'a, R>
where
    R::DynamicType: 'a,
    R: Hash + Debug,
    R::DynamicType: Debug,
{
    fn fmt(&self, f: &mut Formatter<'_>) -> FmtResult {
        f.debug_struct("ResourceRef")
            .field("dynamic_type", &self.dynamic_type)
            .field("group", &self.group)
            .field("kind", &self.kind)
            .field("name", &self.name)
            .finish()
    }
}

// Manual implementation of Hash because the derived impl would require R: Hash.
impl<'a, R: Resource> Hash for ResourceRef<'a, R>
where
    R::DynamicType: 'a,
    R: Hash,
{
    fn hash<H: Hasher>(&self, state: &mut H) {
        self.dynamic_type.hash(state);
        self.group.hash(state);
        self.kind.hash(state);
        self.name.hash(state);
    }
}

impl<R: Resource> ResourceRef<'_, R>
where
    R::DynamicType: 'static + Default,
{
    /// Create a new `ResourceRef` from a concrete `Resource`.
    pub fn new(resource: R) -> Self {
        let name = resource
            .meta()
            .name
            .expect("Resource must have a name");
        Self::new_named(&name)
    }

    /// Create a new `ResourceRef` from just a name.
    ///
    /// This is the place where the lifetime trick happens: we first put the
    /// owned `dynamic_type` into the struct, then we borrow from it to fill
    /// the `group` and `kind` fields.
    pub fn new_named(name: &str) -> Self {
        // 1. Create the owned dynamic data.
        let dynamic_type = R::DynamicType::default();

        // 2. Build the struct with placeholder `None`s for the borrowed fields.
        let mut this = Self {
            type_: PhantomData,
            dynamic_type,
            group: None,
            kind: None,
            name: name.to_string(),
        };

        // 3. Now that `dynamic_type` lives inside `this`, we can borrow from it.
        //    The returned `Cow`s have a lifetime tied to the borrow of
        //    `this.dynamic_type`, which is exactly the lifetime we need for the
        //    struct fields.
        let group = R::group(&this.dynamic_type);
        let kind = R::kind(&this.dynamic_type);

        this.group = Some(group);
        this.kind = Some(kind);

        this
    }

    /// Returns the resource group.
    pub fn group(&self) -> &str {
        self.group
            .as_ref()
            .map(|cow| cow.as_ref())
            .unwrap_or("")
    }

    /// Returns the resource kind.
    pub fn kind(&self) -> &str {
        self.kind
            .as_ref()
            .map(|cow| cow.as_ref())
            .unwrap_or("")
    }

    /// Returns the resource name.
    pub fn name(&self) -> &str {
        &self.name
    }
}

// --- Example usage ---

fn main() {
    // Create a resource instance.
    let resource = MyResource {
        meta: ResourceMeta {
            name: Some("my_resource".to_string()),
        },
    };

    // Build the key.
    let key = ResourceRef::<MyResource>::new_named("my_resource");

    // Print the components.
    println!(
        "key: group = \"{}\", kind = \"{}\", name = \"{}\"",
        key.group(),
        key.kind(),
        key.name()
    );

    // Use the key in a HashMap.
    let mut map = HashMap::new();
    map.insert(key, "the associated value");

    // Lookup using a fresh key with the same contents.
    let lookup_key = ResourceRef::<MyResource>::new_named("my_resource");
    if let Some(value) = map.get(&lookup_key) {
        println!("Found value: {}", value);
    } else {
        println!("Key not found (should not happen)");
    }
}
"
}

