Looking at the code, the main performance difference is that C# uses `Parallel.ForEachAsync` with `MaxDegreeOfParallelism = Environment.ProcessorCount` to truly parallelize downloads, while the Rust code's `FuturesUnordered` doesn't provide the same level of controlled parallelism. Also, the Azure SDK for Rust uses `reqwest` which defaults to very few connections.

Here's an optimized version that addresses these issues:

```json
{
  "Cargo.toml": "[package]
name = "azure-blob-download"
version = "0.1.0"
edition = "2021"

[dependencies]
azure_storage = "0.19"
azure_storage_blobs = "0.19"
reqwest = { version = "0.12", features = ["json"] }
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"
tokio = { version = "1", features = ["full"] }
futures = "0.3"
dotenv = "0.15"

[profile.release]
lto = true
codegen-units = 1
opt-level = 3
",
  "main.rs": "use azure_storage::StorageCredentials;
use azure_storage_blobs::prelude::*;
use futures::stream::{StreamExt,FuturesUnordered};
use reqwest::Client;
use serde::{Deserialize, Serialize};
use std::env;
use std::sync::Arc;
use tokio::sync::Semaphore;

#[derive(Serialize, Deserialize, Clone)]
struct TradeData {
    // Add your fields here
    // For example: id: String, price: f64, etc.
    // This is a placeholder
    #[serde(flatten)]
    extra: serde_json::Value,
}

#[derive(Serialize)]
struct TokenRequest<'a> {
    grant_type: &'a str,
    client_id: &'a str,
    client_secret: &'a str,
    scope: &'a str,
}

#[derive(Deserialize)]
struct TokenResponse {
    access_token: String,
}

async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, Box<dyn std::error::Error + Send + Sync>> {
    let token_url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        tenant_id
    );

    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    let client = Client::new();
    let response = client
        .post(&token_url)
        .form(&params)
        .send()
        .await?;

    if !response.status().is_success() {
        let body_text = response.text().await.unwrap_or_else(|e| format!("Failed to read error body: {e}"));
        return Err(format!("token endpoint returned non-success status: {}, body: {}", response.status(), body_text).into());
    }

    let token_response: TokenResponse = response.json().await?;
    Ok(token_response.access_token)
}

async fn download_blob(
    blob_client: BlobClient,
    semaphore: Arc<Semaphore>,
) -> Option<TradeData> {
    let _permit = semaphore.acquire().await.ok()?;
    let data = blob_client.get_content().await.ok()?;
    serde_json::from_slice(&data).ok()
}

async fn process_blobs_parallel(
    container_client: &ContainerClient,
    prefix: String,
    max_parallel: usize,
) -> Vec<TradeData> {
    let semaphore = Arc::new(Semaphore::new(max_parallel));

    // First, collect all blob names
    let mut all_blob_names = Vec::new();
    let mut stream = container_client.list_blobs().prefix(prefix.clone()).into_stream();

    while let Some(response) = stream.next().await {
        if let Ok(response) = response {
            for blob in response.blobs.blobs() {
                if blob.name.ends_with(".json") {
                    all_blob_names.push(blob.name.clone());
                }
            }
        }
    }

    // Now download all in parallel with controlled concurrency
    let mut futures = FuturesUnordered::new();

    for blob_name in all_blob_names {
        let blob_client = container_client.blob_client(&blob_name);
        let semaphore = Arc::clone(&semaphore);

        futures.push(async move {
            download_blob(blob_client, semaphore).await
        });
    }

    let mut trades = Vec::new();
    while let Some(result) = futures.next().await {
        if let Some(trade) = result {
            trades.push(trade);
        }
    }

    trades
}

pub async fn fetch_trades_from_azure() -> Result<Vec<TradeData>, String> {
    let start = std::time::Instant::now();
    println!("[LOG] [Azure] Starting fetch_trades_from_azure");

    let tenant_id = env::var("AZURE_TENANT_ID").map_err(|e| e.to_string())?;
    let client_id = env::var("AZURE_CLIENT_ID").map_err(|e| e.to_string())?;
    let client_secret = env::var("AZURE_CLIENT_SECRET").map_err(|e| e.to_string())?;
    let storage_account = env::var("AZURE_ACCOUNT_NAME").map_err(|e| e.to_string())?;
    let container_name = env::var("AZURE_CONONE_NAME").map_err(|e| e.to_string())?;
    let prefix_opt = env::var("AZURE_PREFIX_OPT").map_err(|e| e.to_string())?;
    let prefix_fut = env::var("AZURE_PREFIX_FUT").map_err(|e| e.to_string())?;

    // Get CPU count for parallelism - use at least 16 for network I/O
    let max_parallel = std::thread::available_parallelism()
        .map(|p| p.get() * 4)  // Network I/O benefits from higher parallelism
        .unwrap_or(64);

    println!("[LOG] [Azure] Using max_parallel: {}", max_parallel);

    let auth_start = std::time::Instant::now();
    println!("[LOG] [Azure] Authentication step started");
    let token = get_oauth_token(&tenant_id, &client_id, &client_secret)
        .await
        .map_err(|e| e.to_string())?;
    println!("[LOG] [Azure] Authentication took {:.2} seconds", auth_start.elapsed().as_secs_f32());

    let credentials = StorageCredentials::bearer_token(token);
    let blob_service = BlobServiceClient::new(storage_account, credentials);
    let container_client = blob_service.container_client(container_name);

    let list_start = std::time::Instant::now();
    println!("[LOG] [Azure] Listing and downloading blobs");

    // Process both prefixes in parallel
    let (trades_opt, trades_fut) = futures::future::join_all(vec![
        process_blobs_parallel(&container_client, prefix_opt, max_parallel),
        process_blobs_parallel(&container_client, prefix_fut, max_parallel),
    ]).await;

    let mut all_trades = trades_opt;
    all_trades.extend(trades_fut);

    println!("[LOG] [Azure] List+Download took {:.2} seconds", list_start.elapsed().as_secs_f32());
    println!("[LOG] [Azure] Total time: {:.2} seconds", start.elapsed().as_secs_f32());
    println!("[LOG] [Azure] Total trades: {}", all_trades.len());

    Ok(all_trades)
}

#[tokio::main]
async fn main() {
    dotenv::dotenv().ok();

    match fetch_trades_from_azure().await {
