    InvalidInput(String),
}

impl APIError {
    fn invalid_input(msg: &str) -> Self {
        APIError::InvalidInput(msg.to_string())
    }
}

impl IntoResponse for APIError {
    fn into_response(self) -> Response {
        let (status, body) = match self {
            APIError::InvalidInput(msg) => (StatusCode::BAD_REQUEST, msg),
        };
        (status, body).into_response()
    }
}

#[derive(Clone, Debug)]
pub struct SharedState {}

#[derive(Debug, Deserialize, Validate)]
pub struct RevokeUser {
    #[validate(length(min = 6, message = r#"user_id must be at least 6 characters"#))]
    pub user_id: String,
}

pub struct ValidatedJson<T>(pub T);

#[async_trait]
impl<T, S> FromRequest<S> for ValidatedJson<T>
where
    T: Deserialize + Validate + Send + 'static,
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request(req: Request, state: &S) -> Result<Self, Self::Rejection> {
        let Json(payload) = Json::from_request(req, state).await?;
        payload.validate().map_err(|e| APIError::invalid_input(&e.to_string()))?;
        Ok(ValidatedJson(payload))
    }
}

#[derive(Debug)]
pub struct ApiVersionHeader(pub String);

#[async_trait]
impl FromRequestParts<SharedState> for ApiVersionHeader {
    type Rejection = APIError;

    async fn from_request_parts(
        parts: &mut axum::http::Parts,
        _state: &SharedState,
    ) -> Result<Self, Self::Rejection> {
        let version = parts
            .headers
            .get(r#"x-api-version"#)
            .and_then(|v| v.to_str().ok())
            .map(|s| s.to_string())
            .ok_or_else(|| APIError::invalid_input(r#"Missing X-Api-Version header"#))?;
        Ok(ApiVersionHeader(version))
    }
}

#[derive(Debug)]
pub struct AccessClaims {
    pub sub: String,
}

#[async_trait]
impl FromRequestParts<SharedState> for AccessClaims {
    type Rejection = APIError;

    async fn from_request_parts(
        parts: &mut axum::http::Parts,
        _state: &SharedState,
    ) -> Result<Self, Self::Rejection> {
        let auth = parts
            .headers
            .get(r#"authorization"#)
            .and_then(|v| v.to_str().ok())
            .map(|s| s.to_string())
            .ok_or_else(|| APIError::invalid_input(r#"Missing Authorization header"#))?;
        Ok(AccessClaims { sub: auth })
    }
}

async fn revoke_user_handler(
    ApiVersionHeader(api_version): ApiVersionHeader,
    State(state): State<SharedState>,
    access_claims: AccessClaims,
    ValidatedJson(revoke_user): ValidatedJson<RevokeUser>,
) -> impl IntoResponse {
    let _ = (api_version, state, access_claims, revoke_user);
    (StatusCode::OK, r#"OK"#)
}

#[tokio::main]
async fn main() {
