/// Transform a path by removing the segment "devices" that directly follows "vexide".
fn transform_path(path: &str) -> String {
    let segments: Vec<&str> = path.split("::").collect();
    let mut result = Vec::new();
    let mut i = 0;
    while i < segments.len() {
        let seg = segments[i];
        if seg == "vexide" && i + 1 < segments.len() && segments[i + 1] == "devices" {
            // skip the following segment ("devices")
            i += 2;
        } else {
            result.push(seg);
            i += 1;
        }
    }
    result.join("::")
}

/// Compute the suffix (the path component for the current node) after applying the transformation,
/// given the transformed full path and the prefix that precedes this node.
fn compute_suffix(full: &str, prefix: &Option<String>) -> String {
    match prefix {
        None => full.to_string(),
        Some(pfx) => {
            if full.starts_with(pfx) {
                let suffix = &full[pfx.len()..];
                suffix.trim_start_matches("::").to_string()
            } else {
                // Should not happen, but just return full path
                full.to_string()
            }
        }
    }
}
