```json
{
  "Cargo.toml": "[package]
name = "cli-node-example"
version = "0.1.0"
edition = "2021"

[dependencies]
clap = { version = "4.5", features = ["derive"] }
",
  "main.rs": "use clap::{Args, Parser, Subcommand};

/// CLI for node management
#[derive(Parser)]
#[command(name = "cli")]
#[command(version = "1.0")]
#[command(about = "Node management CLI")]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Node operations
    Node(NodeCommand),
}

/// Node command that handles multiple patterns:
/// - cli node create <NAME>
/// - cli node get <NAME>
/// - cli node <NAME> link <TARGET>
#[derive(Args)]
#[command(arg_required_else_help = true)]
struct NodeCommand {
    /// The action to perform (create, get) or the node name
    #[arg(hide_help_short = true)]
    name_or_action: String,

    /// Remaining arguments:
    /// - For create/get: this is the NAME
    /// - For node operations: this is the action (e.g., "link") and its args
    #[arg(hide_help_short = true, last = true)]
    remaining: Vec<String>,
}

impl NodeCommand {
    fn parse_mode(&self) -> NodeParseMode {
        match self.name_or_action.as_str() {
            "create" | "get" => {
                // cli node create <NAME> or cli node get <NAME>
                let name = self.remaining.first().cloned().unwrap_or_default();
                NodeParseMode::Action {
                    action: self.name_or_action.clone(),
                    name,
                }
            }
            _ => {
                // cli node <NAME> link <TARGET> or cli node <NAME>
                let node_name = self.name_or_action.clone();
                let action = self.remaining.first().cloned();
                let target = self.remaining.get(1).cloned();

                NodeParseMode::NodeOperation {
                    node_name,
                    action,
                    target,
                }
            }
        }
    }
}

enum NodeParseMode {
    Action {
        action: String,
        name: String,
    },
    NodeOperation {
        node_name: String,
        action: Option<String>,
        target: Option<String>,
    },
}

fn handle_node_command(node_cmd: NodeCommand) {
    match node_cmd.parse_mode() {
        NodeParseMode::Action { action, name } => match action.as_str() {
            "create" => {
                if name.is_empty() {
                    eprintln!("Error: NAME is required for 'create' command");
                    std::process::exit(1);
                }
                println!("Creating node '{}'", name);
            }
            "get" => {
                if name.is_empty() {
                    eprintln!("Error: NAME is required for 'get' command");
                    std::process::exit(1);
                }
                println!("Getting node '{}'", name);
            }
            _ => {
                unreachable!("This should not happen due to clap constraints");
            }
        },
        NodeParseMode::NodeOperation {
            node_name,
            action,
            target,
