    }

    /// Dispatches a request to the matching handler.
    async fn handle_request(&self, path: &str, req: &Request) -> Option<Response> {
        let handler = self.routes.get(path)?;
        // `handler.call(req)` returns a `BoxFuture`, which we `.await` directly.
        let response = handler.call(req).await;
