    "main.rs": "use std::env;

fn tokenize(s: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_quote = false;

    for ch in s.chars() {
        if ch == '\'' {
            // Toggle quote state; the quote character itself is removed.
            in_quote = !in_quote;
            continue;
        }

        if in_quote {
            // Inside single quotes, every character is kept verbatim.
            current.push(ch);
        } else {
            if ch.is_whitespace() {
                // Whitespace outside quotes terminates the current token.
                if !current.is_empty() {
                    tokens.push(current);
                    current = String::new();
                }
            } else {
                // Regular character outside quotes: accumulate.
                current.push(ch);
            }
        }
    }

    // Push the final token if present.
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    // By default tokenize the example from the prompt.
