  "main.rs": "use chrono::NaiveDateTime;
use std::error::Error;

fn main() {
    // Test cases from the user's problem
    let test_dates = vec![
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
    ];

    for date_str in test_dates {
        match parse_lancedb_date(date_str) {
            Ok(timestamp) => {
                println!("Last Read: {:?} -> Unix timestamp: {}", date_str, timestamp);
            }
            Err(e) => {
                println!("Date Error: {:?}: {}", date_str, e);
            }
        }
    }
}

/// Parses a LanceDB date string (which may or may not have fractional seconds)
/// and returns the Unix timestamp (seconds since epoch).
fn parse_lancedb_date(d: &str) -> Result<i64, Box<dyn Error>> {
    // Try parsing with fractional seconds first (format with %.f)
    // This handles: "2025-08-02T17:35:41.409"
    if let Ok(dt) = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S%.f") {
        return Ok(dt.timestamp());
    }

    // Fall back to parsing without fractional seconds
    // This handles: "1970-01-01T00:00:00"
    let dt = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S")?;
    Ok(dt.timestamp())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_without_fractional_seconds() {
        let result = parse_lancedb_date("1970-01-01T00:00:00");
        assert!(result.is_ok());
        assert_eq!(result.unwrap(), 0);
    }

    #[test]
    fn test_parse_with_fractional_seconds() {
        let result = parse_lancedb_date("2025-08-02T17:35:41.409");
        assert!(result.is_ok());
        // 2025-08-02 17:35:41 UTC
        assert_eq!(result.unwrap(), 1754153751);
    }

    #[test]
    fn test_parse_all_variants() {
        let test_cases = vec![
            ("1970-01-01T00:00:00", 0),
            ("2025-08-02T17:35:41.409", 1754153751),
            ("2025-08-04T01:48:44.017", 1754286524),
            ("2025-08-04T23:02:20.584", 1754337740),
            ("2025-08-05T00:08:57.350", 1754345337),
            ("2025-08-10T18:31:26.628", 1754837486),
        ];

        for (date_str, expected) in test_cases {
            let result = parse_lancedb_date(date_str).unwrap();
            assert_eq!(result, expected, "Failed for {}", date_str);
        }
    }
}
"
}
