  "main.rs": "use actix_web::{web, App, HttpResponse, HttpServer, Middleware, Service, dev::ServiceRequest};
use log::{info, error};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use tokio::sync::oneshot;

// Simple queue handler that supports graceful shutdown
struct QueueHandler {
    shutdown_tx: Option<oneshot::Sender<()>>,
}

impl QueueHandler {
    fn new() -> (Self, oneshot::Receiver<()>) {
        let (tx, rx) = oneshot::channel();
        (Self { shutdown_tx: Some(tx) }, rx)
    }

    async fn run(self, mut shutdown_rx: oneshot::Receiver<()>) {
        info!("Queue handler started");

        // Wait for either shutdown signal or periodic work
        loop {
            tokio::select! {
                _ = &mut shutdown_rx => {
                    info!("Queue handler received shutdown signal");
                    break;
                }
                _ = tokio::time::sleep(tokio::time::Duration::from_millis(100)) => {
                    // Simulate periodic queue work
                }
            }
        }

        // Graceful shutdown: finish pending work here
        info!("Queue handler finishing pending work...");
        tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
        info!("Queue handler stopped gracefully");
    }
}

// Custom middleware for logging
struct LogMiddleware;

impl<S, B> Middleware<S> for LogMiddleware {
    fn transform(&self, svc: Service<S>) -> ServiceRequest<S, B> {
        info!("Request received");
        svc
