/// Robust implementation using a dedicated thread and channels.
/// This is the pattern recommended for Tauri to avoid freezing the async runtime
/// with blocking PTY I/O, and to solve the Mutex deadlock.
async fn run_agent_robust() {
    let (cmd_tx, cmd_rx) = std::sync::mpsc::channel::<String>();
    let (output_tx, mut output_rx) = tokio::sync::mpsc::Sender<String>();

    // Spawn a standard thread to handle the blocking PTY I/O
    std::thread::spawn(move || {
        let mut session = match spawn_shell() {
            Ok(s) => s,
            Err(_) => return,
        };

        // Use a loop to simulate non-blocking / select behavior
        // In production, use nix::poll or select! with a pipe wakeup.
        loop {
