/// This function polls the future with a waker that does nothing. If the future
/// is already ready (e.g., a `ready()` future or a completed future), it will
/// return `Ready`. If the future needs to wait (returns `Pending`), it means
/// the future hasn't completed yet.
///
/// # Safety
/// 
/// We use `Pin::new_unchecked` because we don't move the future, just poll it
/// in place. The future remains at the same memory location for the duration
/// of this call.
fn try_poll<X>(future: &mut impl Future<Output = X>) -> TryPollResult<X> {
    let waker = Waker::noop();
    let mut cx = Context::from_waker(&waker);

    // SAFETY: We are not moving the future, just polling it once.
    // The future will not be moved until it is dropped.
    match unsafe { Pin::new_unchecked(future) }.poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    println!("=== Manual Future Polling Demo ===\n");

    // Case 1: Future that completes immediately
    println!("Case 1: Future that completes immediately");
    let mut immediate_future = async { 42 };
    match try_poll(&mut immediate_future) {
        TryPollResult::Ready(value) => {
            println!("  ✓ Future ready immediately: {}", value);
        }
        TryPollResult::Pending => {
            println!("  ✗ Future pending (unexpected!)");
        }
    }

    // Case 2: Future that needs to wait (async operation)
    println!("\nCase 2: Future that requires waiting");
    // Box::pin gives us ownership so we can move it to a spawned task if needed
    let mut delayed_future = Box::pin(async {
        tokio::time::sleep(std::time::Duration::from_millis(100)).await;
        42
    });

    match try_poll(delayed_future.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("  ✓ Future ready immediately: {}", value);
        }
        TryPollResult::Pending => {
            println!("  → Future not ready yet, spawning task to wait...");

            // Move the boxed future into a spawned task
            let future = delayed_future;
            let handle = tokio::spawn(async move {
                let result = future.await;
                result
            });

            // Wait for the spawned task to complete
            match handle.await {
                Ok(value) => {
                    println!("  ✓ Spawned task completed with: {}", value);
                }
                Err(e) => {
                    println!("  ✗ Spawned task failed: {:?}", e);
                }
            }
        }
    }

    // Case 3: Using with a non-immediate but ready future (like async that returns Ready)
    println!("\nCase 3: Future from async block that returns Ready immediately");
    let mut ready_future = Box::pin(async {
        // Even with async, we can return immediately
        async { 100 }.await
    });
    match try_poll(ready_future.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("  ✓ Future ready: {}", value);
        }
        TryPollResult::Pending => {
            println!("  ✗ Future pending (unexpected!)");
        }
    }

    println!("\n=== Demo Complete ===");
}
