use serde::Deserialize;
use std::sync::Arc;
use tokio::sync::mpsc;

// The borrowed struct we want to deserialize into
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// An owned version that can be sent across threads ('static)
// This ties the source String with references into it
#[derive(Debug, Clone)]
struct OwnedMyData {
    // The source data - all references point into this string
    source: String,
    // The deserialized data as owned strings that reference source
    data: String,
    more_data: String,
