// Alternative: A more generic wrapper that works with any borrowed struct
// This uses a self-referential pattern
#[derive(Debug, Clone)]
struct OwnedData<T> {
    source: String,
    // We store the owned deserialized version instead
    data: T,
}

// Implement conversion from borrowed to owned
impl OwnedMyData {
    fn from_borrowed<'a>(source: &'a str, borrowed: MyData<'a>) -> Self {
        // We can't simply clone the string slices because they borrow from source
        // Instead, we re-deserialize into owned strings, OR we can use indices
        // For efficiency, let's use a different approach: deserialize to owned directly
        // But we want to deserialize only once...

        // Actually, the clever trick: we can "reconstruct" owned strings from the borrowed ones
        // The borrowed strings point into the original source, so we can extract them
        // by using the pointer distance and recreating from source

        // Since we can't easily get owned strings from &str without cloning,
        // we'll use a workaround: deserialize twice (once for borrowed, once for owned)
        // OR use a smart pointer approach

        // Better approach: use a custom deserializer that gives us owned data directly
        // But let's show the "once deserialization" approach with some tradeoffs

        // Option 1: Store the indices and reconstruct (complex)
        // Option 2: Use std::borrow::Cow to have both worlds

        // Let's go with the simplest working solution:
        // Convert the borrowed references into owned strings by re-using the source data
        // This is actually zero-copy at the deserialization level, just copying the pointers
        // to create owned Strings that share the same buffer (but that's not how Rust works)

        // Actually in Rust, String and &str share memory but when you convert &str to String,
        // it copies. To truly avoid that, we'd need something like arc_str or similar.

        // For the purpose of this example showing the pattern: we'll accept one allocation
        // to create owned strings from the borrowed ones. This is still better than
        // deserializing twice.

        // Calculate positions
        let data_start = borrowed.data.as_ptr() as usize - source.as_ptr() as usize;
        let data_end = data_start + borrowed.data.len();
        let more_data_start = borrowed.more_data.as_ptr() as usize - source.as_ptr() as usize;
        let more_data_end = more_data_start + borrowed.more_data.len();

        // Extract owned strings using the calculated indices
        // This is zero-copy in terms of JSON parsing - we only do slice extraction
        let data = source[data_start..data_end].to_string();
        let more_data = source[more_data_start..more_data_end].to_string();

        Self {
            source,
            data,
            more_data,
        }
    }
}

