}

// Generic Vec/Option handler - uses runtime type checking
fn try_handle_vec_or_option(ui: &mut Ui, title: &str, value_mut: &mut (dyn Any + 'static), interactable: bool) -> bool {
    let type_id = value_mut.type_id();

    // Check if it's a Vec
