fn is_vec_type(type_id: TypeId) -> bool {
    // Check for Vec<String>
    if type_id == std::any::TypeId::of::<Vec<String>>() { return true; }
    if type_id == std::any::TypeId::of::<Vec<i32>>() { return true; }
    if type_id == std::any::TypeId::of::<Vec<f32>>() { return true; }
    if type_id == std::any::TypeId::of::<Vec<bool>>() { return true; }
    if type_id == std::any::TypeId::of::<Vec<DataType>>() { return true; }
    if type_id == std::any::TypeId::of::<Vec<ValueType>>() { return true; }
    if type_id == std::any::TypeId::of::<Vec<NamedTypeValue>>() { return true; }
    if type_id == std::any::TypeId::of::<Vec<ArgumentNamedValue>>() { return true; }
    false
}

fn is_option_type(type_id: TypeId) -> bool {
    if type_id == std::any::TypeId::of::<Option<DataType>>() { return true; }
    if type_id == std::any::TypeId::of::<Option<String>>() { return true; }
    if type_id == std::any::TypeId::of::<Option<usize>>() { return true; }
    false
}

// Dynamic Vec handler - tries all known Vec types
fn handle_vec_dyn(ui: &mut Ui, title: &str, value_mut: &mut (dyn Any + 'static), interactable: bool) {
    let type_id = value_mut.type_id();

    macro_rules! handle_vec {
        ($($t:ty),*) => {
            $(
                if type_id == std::any::TypeId::of::<Vec<$t>>() {
                    if let Some(v) = value_mut.downcast_mut::<Vec<$t>>() {
                        list_property_impl(ui, title, v, interactable);
                        return;
                    }
                }
            )*
        }
    }

    handle_vec! {
        String, i32, f32, bool, DataType, ValueType, NamedTypeValue, ArgumentNamedValue
    }
}

// Dynamic Option handler - tries all known Option types
fn handle_option_dyn(ui: &mut Ui, title: &str, value_mut: &mut (dyn Any + 'static), interactable: bool) {
    let type_id = value_mut.type_id();

    macro_rules! handle_option {
        ($($t:ty),*) = {
            $(
                if type_id == std::any::TypeId::of::<Option<$t>>() {
                    if let Some(o) = value_mut.downcast_mut::<Option<$t>>() {
                        option_propery_impl(ui, title, o, interactable);
                        return;
                    }
                }
            )*
        }
    }

    handle_option! {
        DataType, String, usize
    }
}

// Generic list property implementation
pub fn list_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool)
where
    T: Default + 'static + Any,
{
    list_property_impl(ui, title, value_mut, interactable);
}

fn list_property_impl<T>(ui: &mut Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool)
where
    T: Default + 'static + Any,
{
    // Ensure the Vec is non-null for type checking
    let _ = value_mut;

