#[derive(Deserialize, Debug)]
struct A {
    #[serde(deserialize_with = "deserialize_path_list")]
 path_list: Vec<PathBuf>,
}

/// Deserialize a `Vec<PathBuf>` that may be either a JSON array or a JSON reference
/// object like { "$ref": "./some.json#/path" }.
fn deserialize_path_list<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: de::Deserializer<'de>,
{
    // Deserialize into a generic JSON value first.
    let value = serde_json::Value::deserialize(deserializer).map_err(de::Error::custom)?;

    // If the value is an object that contains a "$ref" key, resolve it.
    if let Some(obj) = value.as_object() {
        if let Some(reference) = obj.get("$ref").and_then(|v| v.as_str()) {
            // Resolve the reference and return the resulting vector.
            let resolved = resolve_reference(reference).map_err(de::Error::custom)?;
            return Ok(resolved);
        }
    }

    // Otherwise treat the value as a plain sequence of paths.
    let seq = serde_json::from_value::<Vec<PathBuf>>(value).map_err(|e| de::Error::custom(e.to_string()))?;
    Ok(seq)
}

/// Resolve a JSON reference string (e.g. "./a.json#/p_list") to the referenced
/// JSON array and deserialize it as a `Vec<PathBuf>`.
fn resolve_reference(reference: &str) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
    // Split the reference into the file part and the JSON pointer part.
    let (file_part, pointer_part) = reference.split_once('#').map(|(f, p)| (f, Some(p))).unwrap_or((reference, None));

    // Remove a leading "./" if present – it's common in JSON references.
    let file_path = file_part.trim_start_matches('./');

    // Read the referenced JSON file.
    let content = fs::read_to_string(file_path)?;

    // Parse the whole JSON document.
    let json: serde_json::Value = serde_json::from_str(&content)?;

    // Navigate to the JSON pointer if it exists.
    let target = if let Some(pointer) = pointer_part {
        let pointer = pointer.strip_prefix('/').unwrap_or(pointer);
        let pointer = format!("/{}", pointer);
        json.pointer(&pointer).ok_or_else(|| format!("JSON pointer '{}' not found in file '{}'", pointer, file_path))?
    } else {
        json
    };

    // Deserialize the targeted sub‑value as a vector of PathBuf.
    let result = serde_json::from_value::<Vec<PathBuf>>(target)?;
    Ok(result)
}
"
