fn process_use_tree(tree: &UseTree, edits: &mut Vec<(Range<usize>, String)>) {
    // Process nested trees first
    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            process_use_tree(&child, edits);
        }
    }

    // Rewrite the path of this tree, removing any segment called "devices"
    if let Some(path) = tree.path() {
        let old_path = path.to_string();
        let new_segments: Vec<String> = path
            .segments()
            .filter(|seg| seg.to_string() != "devices")
            .map(|seg| seg.to_string())
            .collect();
        let new_path = new_segments.join("::");

        if new_path != old_path {
            let range = path.range();
            let start = range.start().0 as usize;
            let end = range.end().0 as usize;
            edits.push((start..end, new_path));
        }
    }
}

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <file.rs>", args[0]);
        return;
    }

    let file_path = &args[1];
    let source = fs::read_to_string(file_path).expect("Failed to read the file");

    let source_file = SourceFile::parse(&source).tree();
    let root = source_file.syntax().clone();

    // Locate all use items
    let use_items: Vec<Use> = root
        .descendants()
        .filter_map(Use::cast)
        .collect();

    let mut edits = Vec::new();

    for use_item in use_items {
        if let Some(tree) = use_item.use_tree() {
            process_use_tree(&tree, &mut edits);
        }
    }

    // Sort edits by start position descending to apply later ranges first
    edits.sort_by(|a, b| b.start.cmp(&a.start));

    let mut new_source = source;
    for (range, new_text) in edits {
        new_source.replace_range(range, &new_text);
    }

