impl AssetReader for ZipAssetReader {
    fn read_asset_bytes<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Bytes, Box<dyn std::error::Error + Send + Sync>>> {
        Box::pin(async move {
            // Open the zip file
            let file = std::fs::File::open(&self.zip_path)
                .map_err(|e| Box::new(e) as Box<dyn std::error::Error + Send + Sync>)?;
            let mut archive = ZipArchive::new(file)
                .map_err(|e| Box::new(e) as Box<dyn std::error::Error + Send + Sync>)?;

            // Look up the entry by name (the path after the "zip://" scheme)
            let path_str = path.to_string_lossy();
            let mut entry = archive.by_name(&path_str).map_err(|_| {
                let err = std::io::Error::new(
                    std::io::ErrorKind::NotFound,
                    format!("Entry not found in zip: {}", path_str),
                );
