{
  "Cargo.toml": "[package]
name = "broadcast_shutdown_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
tokio-stream = { version = "0.1", features = ["broadcast"] }
futures = "0.3"
",
  "main.rs": "use std::sync::Arc;
use tokio::sync::broadcast;
use tokio::time;
use tokio_stream::broadcast::BroadcastStream;
use tokio_stream::StreamExt;
use futures::Stream;

#[derive(Debug, Clone)]
pub struct Event {
    pub payload: String,
}

#[derive(Clone)]
pub struct EventSender {
    tx: Arc<broadcast::Sender<Event>>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

pub struct EventStreamFactory {
    tx: Arc<broadcast::Sender<Event>>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, broadcast::RecvError>> + Send + '_ {
        let receiver = self.tx.subscribe();
        BroadcastStream::new(receiver)
    }
}

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel(20);
    let tx = Arc::new(tx);
    (EventSender { tx: tx.clone() }, EventStreamFactory { tx })
}

#[tokio::main]
async fn main() {
    let (event_sender, event_factory) = events_channel();

    // Spawn a producer that sends an event every second.
    let sender = event_sender.clone();
    let producer = tokio::spawn(async move {
        let mut counter = 0usize;
        loop {
            time::sleep(std::time::Duration::from_secs(1)).await;
            counter += 1;
            let event = Event {
                payload: format!("event-{}", counter),
            };
            if sender.send(event).is_err() {
                println!("[producer] channel closed, stopping");
                break;
            }
            println!("[producer] sent event-{}", counter);
        }
    });

    // Spawn a consumer that prints received events.
    let mut stream = event_factory.all_events();
    let consumer = tokio::spawn(async move {
        while let Some(result) = stream.next().await {
            match result {
                Ok(event) => println!("[consumer] received: {:?}", event.payload),
                Err(e) => {
                    println!("[consumer] stream error: {:?}", e);
                    break;
                }
            }
        }
        println!("[consumer] stream finished");
    });

    // Wait for Ctrl+C to initiate shutdown.
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            println!("[main] Received Ctrl-C, initiating shutdown...");
        }
    }

    // Drop the factory and sender, which closes the broadcast channel.
    drop(event_factory);
    drop(event_sender);

    // Wait for the producer and consumer tasks to finish.
    let _ = producer.await;
    let _ = consumer.await;

    println!("[main] Done");
}
"
}

