    let (event_tx, event_rx) = unbounded::<Message>();
    // Channel used to request all threads to stop.
    let (stop_tx, stop_rx) = unbounded::<()>();

    // ── Input thread ────────────────────────────────────────────────────────
    // Reads characters from stdin and forwards them as Messages.
    // It checks the stop channel each iteration, so it can be aborted promptly.
    let event_tx_in = event_tx.clone();
    let stop_rx_in = stop_rx.clone();

