serde_json = "1.0"
",
  "main.rs": "use serde::de::{self, MapAccess, Visitor};
use serde::Deserialize;
use serde_json::Value;
use std::fmt;

#[derive(Debug)]
struct Character {
    name: String,
    server: String,
}

impl<'de> Deserialize<'de> for Character {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        struct CharacterVisitor;

        impl<'de> Visitor<'de> for CharacterVisitor {
            type Value = Character;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a map with fields \"name\" and \"server\"")
            }

            fn visit_map<A>(self, mut map: A) -> Result<Self::Value, A::Error>
            where
                A: MapAccess<'de>,
            {
                let mut name: Option<String> = None;
                let mut server: Option<String> = None;

                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "name" => {
                            if name.is_some() {
                                return Err(de::Error::duplicate_field("name"));
                            }
                            name = Some(map.next_value()?);
                        }
                        "server" => {
                            if server.is_some() {
                                return Err(de::Error::duplicate_field("server"));
                            }
                            // Deserialize the nested object as a JSON value.
                            let server_value: Value = map.next_value()?;
                            // Extract the "name" field from the server object.
                            if let Some(Value::String(server_name)) = server_value.get("name") {
                                server = Some(server_name.clone());
                            } else {
                                return Err(de::Error::custom("expected server to have a 'name' field"));
                            }
                        }
                        _ => {
                            // Skip unknown fields.
                            let _: Value = map.next_value()?;
                        }
                    }
                }

                let name = name.ok_or_else(|| de::Error::missing_field("name"))?;
                let server = server.ok_or_else(|| de::Error::missing_field("server"))?;

                Ok(Character { name, server })
            }
        }

        deserializer.deserialize_map(CharacterVisitor)
    }
}

fn main() {
    let json = "{\n    \"name\": \"Name\",\n    \"server\": {\n        \"name\": \"Server\"\n    }\n}";

    let character: Character = serde_json::from_str(json).expect("failed to deserialize JSON");
    println!("{:?}", character);
}
"
}

