// Macro that generates the nested‑module trick.
// --------------------------------------------------------------------------
// The macro expects a simple identifier (e.g. `MyStruct`).  It creates a
// uniquely‑named module (`_tmp_<Ident>`) that imports the type, then
// defines an `go` function that calls the inherent method.  The generated
// `impl Foo for Ident` simply forwards to that function.
//
// Because the nested module does *not* import the trait `Foo`, the call
// `this.go()` can only resolve to an inherent method.  If none exists,
// the compiler emits an error.
// --------------------------------------------------------------------------
macro_rules! derive_foo {
    ($ty:ident) => {
        mod _tmp_$ty {
            use super::$ty;

            #[inline]
            pub fn go(this: &$ty) {
                // The trait is not in scope here, so this must be an inherent method.
                // If `go` is not defined on `$ty` we get a compile‑time error.
                this.go()
            }
        }

        impl Foo for $ty {
            fn go(&self) {
                _tmp_$ty::go(self)
            }
        }
    };
}

