","main.rs":"use std::env;

/// Split a shell command line into tokens, respecting single‑ and double‑quote
/// boundaries. Inside a quoted region whitespace is preserved; outside,
/// whitespace separates tokens. Quote characters themselves are removed.
///
/// # Example
///
/// ```rust
/// let tokens = split_shell_token(" one  ' two  'three    four");
/// assert_eq!(tokens, vec!["one", " two  three", "four"]);
/// ```
pub fn split_shell_token(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut quote: Option<char> = None;

    let chars: Vec<char> = input.chars().collect();
    let mut i = 0;

    while i < chars.len() {
        let ch = chars[i];
        match quote {
            None => {
                if ch.is_whitespace() {
                    // End current token if any
                    if !current.is_empty() {
                        tokens.push(current.clone());
                        current.clear();
                    }
                    // Skip any extra whitespace – they do not create empty tokens.
                } else if ch == '\\' || ch == '\"' {
                    // Start a quoted region.
                    quote = Some(ch);
                } else {
                    current.push(ch);
                }
            }
            Some(q) => {
                if ch == q {
                    // End the quoted region.
                    quote = None;
                } else {
                    // Inside quotes – copy everything (including whitespace).
                    current.push(ch);
                }
            }
        }
        i += 1;
    }

    // Push final token if present.
    if !current.is_empty() {
        tokens.push(current);
    }

    tokens
}

fn main() {
    // If a command line argument is given, tokenize that; otherwise
    // use the example from the problem statement.
    let args: Vec<String> = env::args().collect();
    let input = if args.len() > 1 {
        args[1..].join(" ")
    } else {
        " one  ' two  'three    four".to_string()
    };

    let tokens = split_shell_token(&input);
    for token in tokens {
        println!("<{}>", token);
    }
}
"}

