struct Channel {
    channel_index: AtomicUsize,
}

impl Channel {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Returns the current index and increments the internal counter.
    /// The operation is protected by a critical section, so we can use
    /// `Ordering::Relaxed` because the critical section already guarantees
    /// exclusive access. Using a stronger ordering would add unnecessary
    /// overhead.
    fn next_index(&self) -> usize {
        critical_section::with(|_cs| {
            // Load the current value with relaxed ordering.
            let old_val = self.channel_index.load(Ordering::Relaxed);
            // Store the incremented value with relaxed ordering.
            self.channel_index.store(old_val.wrapping_add(1), Ordering::Relaxed);
            // Return the old value (the index we just allocated).
            old_val
        })
    }
}

