use rustyline::keymap::KeyEvent;
use rustyline::{KeyCode, Modifiers, Event};
use rustyline::Cmd;
use rustyline::Movement;
use rustyline::RepeatCount;
use rustyline::event_handler::{EventHandler, ConditionalEventHandler, EventContext};
use rustyline::error::ReadlineError;

/// Custom conditional event handler that removes any whitespace before the cursor
/// before inserting the configured character.
struct MyEventHandler {
    insert: char,
}

impl MyEventHandler {
    fn new(c: char) -> Self {
        MyEventHandler { insert: c }
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Nothing to do at the start of the line.
        if pos == 0 {
            return None;
        }

        let prefix = &line[..pos];

        // Count how many whitespace characters appear at the end of the prefix.
        let whitespace_count = if let Some(idx) = prefix.rfind(|c| !c.is_whitespace()) {
            // Characters after the last non‑whitespace character.
            pos.saturating_sub(idx + 1)
        } else {
            // The whole prefix is whitespace.
            pos
        };

        if whitespace_count == 0 {
            // No preceding whitespace – let the default handler insert the character.
            return None;
        }

        // Delete the whitespace and then insert the requested character.
        // Using a sequence ensures both actions are performed.
        let kill = Cmd::Kill(Movement::BackwardChar(whitespace_count as RepeatCount));
        let insert = Cmd::SelfInsert(self.insert);
        Some(Cmd::Sequence(vec![kill, insert]))
    }
}

fn main() -> Result<()> {
    let config = Config::builder()
        .auto_add_history(true)
        .build();

    let mut rl = Editor::new(config, "myapp")?;

