    let dot_event = KeyEvent::new(KeyCode::Char('.'), Modifiers::NONE);
    let comma_event = KeyEvent::new(KeyCode::Char(','), Modifiers::NONE);

    let dot_handler = EventHandler::Conditional(Box::new(MyEventHandler::new('.')));
    let comma_handler = EventHandler::Conditional(Box::new(MyEventHandler::new(',')));

