    vrev32q_u32,
    vst1q_u32,
};

// Generic fallback implementation using swap_nonoverlapping.
fn flip_line_generic(line: &mut [u8]) {
    assert_eq!(line.len(), LINE_SIZE);
    let mut left = 0;
    let mut right = line.len() - BYTES_PER_PIXEL;
    while left < right {
        unsafe {
            let pL = line.as_mut_ptr().add(left);
            let pR = line.as_mut_ptr().add(right);
            ptr::swap_nonoverlapping(pL, pR, BYTES_PER_PIXEL);
        }
        left += BYTES_PER_PIXEL;
        right -= BYTES_PER_PIXEL;
    }
