/// Fast SIMD implementation for x86_64 (SSE2)
#[cfg(target_arch = "x86_64")]
unsafe fn flip_line_fast(line: &mut [u8]) {
    debug_assert_eq!(line.len(), LINE_SIZE);
    // Load two 128-bit halves (16 bytes each)
    let left = _mm_loadu_si128(line.as_ptr() as *const __m128i);
    let right = _mm_loadu_si128(line.as_ptr().add(16) as *const __m128i);
    // Reverse the order of the 4-byte elements within each 128-bit register.
    // _MM_SHUFFLE(3,2,1,0) = 0x1B.
    let left_rev = _mm_shuffle_epi32(left, 0x1B);
    let right_rev = _mm_shuffle_epi32(right, 0x1B);
    // Store swapped halves.
    _mm_storeu_si128(line.as_mut_ptr() as *mut __m128i, right_rev);
    _mm_storeu_si128(line.as_mut_ptr().add(16) as *mut __m128i, left_rev);
