    type Asset = Image;

    fn load(&self, reader: &mut dyn Read, _settings: &AssetLoadSettings, path: &AssetPath) -> Result<LoadedAsset<Self::Asset>, AssetLoaderError> {
        // Read entire file into memory
        let mut buffer = Vec::new();
        reader.read_to_end(&mut buffer).map_err(AssetLoaderError::Io)?;

        // Get entry name from label
        let entry_name = path.label().ok_or_else(|| {
            AssetLoaderError::MissingLabel { extension: "wad".to_string() }
        })?;

        // Open zip archive from buffer
        let cursor = std::io::Cursor::new(buffer);
        let mut archive = ZipArchive::new(cursor).map_err(|e| {
            AssetLoaderError::Io(std::io::Error::new(std::io::ErrorKind::InvalidData, e))
        })?;

        // Find entry
        let mut entry = archive.by_name(entry_name).map_err(|_| {
            AssetLoaderError::Io(std::io::Error::new(std::io::ErrorKind::NotFound, format!("Entry {} not found in archive", entry_name)))
        })?;

        // Read entry data
        let mut entry_data = Vec::new();
        entry.read_to_end(&mut entry_data).map_err(AssetLoaderError::Io)?;

        // Decode image
        let img = image::load_from_memory(&entry_data).map_err(|e| {
            AssetLoaderError::Io(std::io::Error::new(std::io::ErrorKind::InvalidData, e))
        })?;

        // Convert to Bevy Image
        let image = Image::from_dynamic_image(img);

