/// Intermediate representation of an import statement.
#[derive(Debug, Clone)]
struct Import {
    /// Path of this segment, relative to the parent import.
    path: Option<String>,
    /// Whether this segment ends with a wildcard (`*`).
    star: bool,
    /// Nested imports inside braces.
    children: Vec<Import>,
}

/// Parse a `UseTree` AST node into our intermediate representation.
fn parse_import(tree: &UseTree) -> Import {
    let path = tree.path().map(|p| p.to_string());
    let star = tree.star().is_some();
    let children: Vec<Import> = tree
        .use_tree_list()
        .map(|list| list.use_trees().map(|t| parse_import(&t)).collect())
        .unwrap_or_default();
    Import { path, star, children }
}

/// Transform an import according to the flattening rule:
/// replace any occurrence of "vexide::devices" with "vexide".
/// If a node collapses to the same path as its parent, its children are
/// lifted one level up (flattening).
fn transform_import(node: &Import, prefix: Option<&str>) -> Vec<Import> {
    // ---------- 1. Build the full path for this node ----------
    let full_path = match (&prefix.map(|s| s.to_string()), &node.path) {
        (None, None) => None,
        (Some(p), None) => Some(p.clone()),
        (None, Some(c)) => Some(c.clone()),
        (Some(p), Some(c)) => {
            if c.starts_with("::") {
                Some(format!("{}{}", p, c))
            } else {
                Some(format!("{}::{}", p, c))
            }
        }
    };

    // ---------- 2. Apply the rewrite rule ----------
    let new_full_path = full_path.map(|p| {
        if p.starts_with("vexide::devices") {
            let rest = p.strip_prefix("vexide::devices").unwrap();
            if rest.starts_with("::") {
                // "vexide::devices::X" -> "vexide::X"
                format!("vexide{}", rest)
            } else if rest.is_empty() {
                // "vexide::devices" -> "vexide"
                "vexide".to_string()
            } else {
                // Unexpected, keep original
                p
            }
        } else {
            p
        }
    });

    // ---------- 3. Flatten if the node collapses onto its parent ----------
    let flatten = !node.children.is_empty() && new_full_path.as_deref() == prefix;

    if flatten {
        // The node disappears; its children are lifted up.
        let mut result = Vec::new();
        for child in &node.children {
            result.extend(transform_import(child, prefix));
        }
        return result;
    }

    // ---------- 4. Compute the relative path after transformation ----------
    let relative = match (&new_full_path, prefix) {
        (Some(full), Some(parent)) => {
            if full.starts_with(parent) {
                let after = &full[parent.len()..];
                if after.starts_with("::") {
                    Some(after[2..].to_string())
                } else if after.is_empty() {
                    // importing the parent itself
                    None
                } else {
                    Some(after.to_string())
                }
            } else {
                Some(full.clone())
            }
        }
        (Some(full), None) => Some(full.clone()),
        (None, _) => None,
    };

    // ---------- 5. Recursively transform children, using the new full path as prefix ----------
    let new_prefix = new_full_path.as_deref().map(|s| s);
    let transformed_children: Vec<Import> = node
        .children
        .iter()
        .flat_map(|c| transform_import(c, new_prefix))
        .collect();

    vec![Import {
        path: relative,
        star: node.star,
        children: transformed_children,
    }]
}

/// Remove imports that become just `use vexide;` (no star, no children).
fn filter_imports(imports: Vec<Import>) -> Vec<Import> {
    imports
        .into_iter()
        .filter(|imp| {
            !(imp.path.as_deref() == Some("vexide") && !imp.star && imp.children.is_empty())
        })
        .collect()
}

/// Turn a single import node (including its children) into a string.
fn format_import(imp: &Import) -> String {
    // Skip empty nodes (path none, no star, no children)
    if imp.path.is_none() && !imp.star && imp.children.is_empty() {
        return String::new();
    }

    if imp.star {
        // `path::*`
        let path_str = imp.path.as_deref().unwrap_or("");
        return format!("{}::*", path_str);
    }

    if !imp.children.is_empty() {
        // `path::{children}` or just `{children}` if path is None
        let path_prefix = imp
            .path
            .as_deref()
            .map(|p| format!("{}::", p))
            .unwrap_or_default();
        let children_str = imp
            .children
            .iter()
            .map(|c| format_import(c))
            .collect::<Vec<_>>()
            .join(", ");
        return format!("{}{{{}}}", path_prefix, children_str);
    }

    // Leaf without star
    imp.path.as_deref().unwrap_or("").to_string()
}

/// Convert a list of top‑level imports into a complete `use …;` line.
/// Returns an empty string if there are no imports left, indicating the line
/// should be removed.
fn import_list_to_string(imports: &[Import]) -> String {
    if imports.is_empty() {
        return String::new();
    }
    if imports.len() == 1 && imports[0].children.is_empty() {
        let imp = &imports[0];
        let base = imp.path.as_deref().unwrap_or("");
        if imp.star {
            return format!("use {}::*;", base);
        } else {
            return format!("use {};", base);
        }
    }
    // Multiple imports or a single import with children → `use { … };`
    let items: Vec<String> = imports
        .iter()
        .map(|imp| format_import(imp))
        .collect();
    format!("use {{ {} }};", items.join(", "))
}

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <source_file>", args[0]);
        return;
    }
    let source = fs::read_to_string(&args[1]).expect("Unable to read file");

    let parse = SourceFile::parse(&source);
    let root = parse.syntax();

    // Collect all replacements: (range in original source, replacement text)
    let mut replacements: Vec<(std::ops::Range<usize>, String)> = Vec::new();

    for use_item in root.descendants().filter_map(Use::cast) {
        let Some(tree) = use_item.use_tree() else {
            continue;
        };
        // Parse → transform → filter → render
        let import = parse_import(&tree);
        let transformed = transform_import(&import, None);
        let filtered = filter_imports(transformed);
        let new_use_str = import_list_to_string(&filtered);

        // Range of the whole `use …;` statement (including the semicolon)
        let range = use_item.syntax().text_range();
        replacements.push((range.start.offset..range.end.offset, new_use_str));
    }

    // Apply changes in reverse order so that earlier ranges stay valid
    let mut result = source;
    for (range, new_text) in replacements.into_iter().rev() {
        result.replace_range(range, &new_text);
    }

    println!("{}", result);
}
