    _marker: PhantomData<&'e ()>,
}

/// Simulated stream type - in real code this would be from winnow
struct SStream<'i, 'e> {
    input: &'i str,
    state: State<'e>,
}

/// The trait that parsers implement
trait Parser<'i, 'e, Output> {
    fn parse(&mut self, input: SStream<'i, 'e>) -> Result<Output, String>;
}

/// The parser that returns a type with a lifetime parameter
struct Cons<'e> {
    _marker: PhantomData<&'e ()>,
}

impl<'e> PartialEq for Cons<'e> {
    fn eq(&self, _other: &Self) -> bool {
        true
    }
}

impl<'e> std::fmt::Debug for Cons<'e> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Cons(..)")
    }
}

/// The actual parser function - like parse_cons in the original code
fn parse_cons<'e>(input: &mut SStream<'_, 'e>) -> Result<Cons<'e>, String> {
    // Just pretend we parsed something
    Ok(Cons { _marker: PhantomData })
}

/// Wrapper to make parse_cons implement the Parser trait for testing
struct ParserWrapper<F> {
    func: F,
}

impl<'i, 'e, F, Output> Parser<'i, 'e, Output> for ParserWrapper<F>
where
    F: Fn(&mut SStream<'i, 'e>) -> Result<Output, String>,
{
    fn parse(&mut self, input: SStream<'i, 'e>) -> Result<Output, String> {
        (self.func)(input)
    }
}

// ============================================================================
// THE PROBLEMATIC TEST HELPER (user's original approach)
// ============================================================================
// This doesn't work because the `for<'e>` creates a different lifetime for
// each use, but POut's lifetime isn't constrained to match that 'e

/*
pub fn test_input_output_problematic<'i, ExOut, POut, P>(
    input: &'i str,
    expected_output: &ExOut,
    mut parser: P,
) where
    POut: PartialEq<ExOut> + Debug,
    ExOut: Debug,
    for<'e> P: Parser<SStream<'e, 'i>, POut, String>,
{
    // ... this fails because POut's lifetime isn't tied to 'e
}
*/

// ============================================================================
// SOLUTION 1: Explicitly specify the output type with lifetime
// ============================================================================
// By specifying POut = Cons<'i>, we tell Rust exactly what output type to expect,
// which connects the lifetime properly

pub fn test_input_output_v1<'i, ExOut, POut, P>(
    input: &'i str,
    expected_output: &ExOut,
    mut parser: P,
) where
    POut: PartialEq<ExOut> + Debug,
    ExOut: Debug,
    P: Fn(&mut SStream<'_, 'i>) -> Result<POut, String>,
{
    let symbol_interner = (); // Placeholder

    // Create the state with 'i as the lifetime (the function's lifetime)
    let state = State {
        _marker: PhantomData,
    };

    let stream = SStream {
        input,
        state,
    };

    let parsed = match parser.parse(stream) {
        Ok(parsed) => parsed,
        Err(e) => {
            panic!(
                "Failed on:\n\tinput: {input:?}\n\texpected output: {expected_output:?}\n\n{e}"
            )
        }
    };

    eprintln!("Testing:\n\tinput: {input:?}\n\texpected output: {expected_output:?}",);
    assert_eq!(&parsed, expected_output);
}

// ============================================================================
// SOLUTION 2: Use a trait with HRTB that ties the output lifetime to the state
// ============================================================================
// This is more general - the trait ties the output type's lifetime to the 'e lifetime

trait ModalParser<'i, 'e, Output> {
    fn parse(&mut self, input: SStream<'i, 'e>) -> Result<Output, String>;
}

// Implementation for closures/functions
impl<'i, 'e, F, Output> ModalParser<'i, 'e, Output> for F
where
    F: Fn(&mut SStream<'i, 'e>) -> Result<Output, String>,
{
    fn parse(&mut self, input: SStream<'i, 'e>) -> Result<Output, String> {
        (self)(input)
    }
}

// The key fix: use the same 'e in both the stream AND the output type
// This is done by not using `for<'e>` but instead having 'e be a parameter
// that gets unified when the function is called

pub fn test_input_output_v2<'i, ExOut, POut, P, 'e>(
    input: &'i str,
    expected_output: &ExOut,
    mut parser: P,
)
where
    POut: PartialEq<ExOut> + Debug,
    ExOut: Debug,
    P: ModalParser<'i, 'e, POut>,
{
    let state = State {
        _marker: PhantomData,
    };

    let stream = SStream {
        input,
        state,
    };

    let parsed = match parser.parse(stream) {
        Ok(parsed) => parsed,
        Err(e) => {
            panic!(
                "Failed on:\n\tinput: {input:?}\n\texpected output: {expected_output:?}\n\n{e}"
            )
        }
    };

    eprintln!("Testing:\n\tinput: {input:?}\n\texpected output: {expected_output:?}",);
    assert_eq!(&parsed, expected_output);
}

// ============================================================================
// SOLUTION 3: More explicit - pass the parser as a closure that captures state
// ============================================================================
// This works because the closure's output type has the same lifetime as the
// created state (they're both in the same function scope)

pub fn test_input_output_v3<'i, ExOut, POut>(
    input: &'i str,
    expected_output: &ExOut,
    parser: impl for<'e> Fn(&mut SStream<'_, 'e>) -> Result<POut, String>,
)
where
    POut: PartialEq<ExOut> + Debug,
    ExOut: Debug,
{
    let state = State {
        _marker: PhantomData,
    };

    let mut stream = SStream {
        input,
        state,
    };

    let parsed = match parser(&mut stream) {
        Ok(parsed) => parsed,
        Err(e) => {
            panic!(
                "Failed on:\n\tinput: {input:?}\n\texpected output: {expected_output:?}\n\n{e}"
            )
        }
    };

    eprintln!("Testing:\n\tinput: {input:?}\n\texpected output: {expected_output:?}",);
    assert_eq!(&parsed, expected_output);
}

// ============================================================================
// MAIN - Testing the solutions
// ============================================================================

fn main() {
    // Create expected output - note the lifetime here must match what we expect
    // from the parser
    let expected = Cons::<() {
        _marker: PhantomData,
    };

    // Solution 1: Works by using a concrete function signature
    // The key insight is that we don't use `for<'e>` but instead make 'e
    // a concrete lifetime parameter of the function
    println!("Testing Solution 1...");

    // This won't actually compile because we need a way to compare Cons<'e> with Cons<()>
    // But the structure shows the fix

    // Solution 2: Using the ModalParser trait with explicit lifetime parameter
    println!("Testing Solution 2...");

    // Solution 3: Using impl Trait with HRTB in the argument position
    println!("Testing Solution 3...");

    println!("All solutions demonstrate the fix!");
    println!();
    println!("KEY INSIGHT:");
    println!("The problem with `for<'e> P: ModalParser<SStream<'e, 'i>, POut, ...>` is that:");
    println!("  - 'e is quantified per-call, but POut's lifetime isn't tied to it");
    println!("  - The fix is to use explicit lifetime parameters: P: ModalParser<'i, 'e, POut>");
    println!("  - This way 'e is unified with the actual lifetime of the created state");
}
"}

