  "main.rs": "use rustyline::{
    Cmd, ConditionalEventHandler, Editor, Event, EventContext, EventHandler, KeyEvent,
    Modifiers, Movement, RepeatCount,
};

/// Custom event handler that removes any whitespace immediately before the cursor
/// when the user types a "." or "," and then inserts the typed character.
/// The cursor is positioned after the newly inserted character.
struct WsHandler {
    ch: char,
}

impl WsHandler {
    fn new(ch: char) -> Self {
        Self { ch }
    }
}

impl ConditionalEventHandler for WsHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        ctx: &EventContext,
    ) -> Option<Cmd> {
        let pos = ctx.pos();
        let line = ctx.line();
        if pos > line.len() {
            return None;
        }
        let before = &line[..pos];
        // Count trailing whitespace characters right before the cursor
        let ws_count = before.chars().rev().take_while(|c| c.is_whitespace()).count();
        if ws_count == 0 {
            // No whitespace – let the default insert happen
            return None;
        }
        // Delete the whitespace (move left) and replace it with our character
        let movement = Movement::BackwardChar(ws_count as RepeatCount);
        let replace = Cmd::Replace(movement, Some(self.ch.to_string()));
        // After the replacement, move one character forward so the cursor ends up
        // after the newly inserted character.
        let move_forward = Cmd::Move(Movement::ForwardChar(1));
        Some(Cmd::Multiple(vec![replace, move_forward]))
    }
}

/// Bind a conditional event handler for a given character.
fn bind_ws_handler(editor: &mut Editor<()>, ch: char) {
    let key = KeyEvent::new(ch, Modifiers::NONE);
    let handler = WsHandler::new(ch);
    let handler = EventHandler::Conditional(Box::new(handler));
    editor.bind_sequence(key, handler);
