use tokio::io::{AsyncReadExt, AsyncWriteExt};
use rustyline_async::Editor;
use rustyline::completion::{Completer, Pair};
use rustyline::Helper;

/// Simple completion for Python keywords
struct PythonCompleter;

impl Completer for PythonCompleter {
    type Candidate = Pair;

    fn complete(&self, line: &str, _pos: usize) -> rustyline::Result<Vec<Pair>> {
        let keywords = vec![
            "print", "if", "else", "elif", "for", "while", "def", "return",
            "import", "from", "class", "True", "False", "None", "and", "or",
            "not", "in", "is", "lambda", "with", "as", "try", "except",
            "finally", "raise", "assert", "break", "continue", "pass", "global",
            "nonlocal", "del", "yield", "async", "await",
        ];
        let matches: Vec<Pair> = keywords
            .iter()
            .filter(|c| c.starts_with(line))
            .map(|c| Pair {
                display: c.to_string(),
                replacement: c.to_string(),
            })
            .collect();
        Ok(matches)
    }
}

impl Helper for PythonCompleter {}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Create the async editor with a simple completer
    let mut rl: Editor<PythonCompleter> = Editor::new();

    // Optionally load command history from a file
    let _ = rl.load_history("history.txt");

    // Spawn the child REPL (Python interactive)
    let mut child = tokio::process::Command::new("python3")
        .args(["-i", "-u"]) // -u for unbuffered output
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .expect("Failed to start child process");

    // Take ownership of the pipes so we can copy data from them
    let mut child_stdout = child.stdout.take().expect("Failed to capture stdout");
    let mut child_stderr = child.stderr.take().expect("Failed to capture stderr");

    // Spawn background tasks that forward child output to our stdout/stderr.
    // This runs concurrently with readline, solving the blocking issue.
    let mut stdout = tokio::io::stdout();
    let mut stderr = tokio::io::stderr();

    tokio::spawn(async move {
        let _ = tokio::io::copy(&mut child_stdout, &mut stdout).await;
    });

    tokio::spawn(async move {
        let _ = tokio::io::copy(&mut child_stderr, &mut stderr).await;
    });

    // Main loop: read user input and forward it to the child REPL
    loop {
        match rl.readline().await {
            Ok(Some(line)) => {
                // Send the line to the child’s stdin
                if let Some(ref mut stdin) = child.stdin {
                    stdin.write_all(line.as_bytes()).await?;
                    stdin.write_all(b"\n").await?;
                    stdin.flush().await?;
                }
                // Add the line to the history
                rl.add_history_entry(line.as_str());
            }
            Ok(None) => {
                // EOF (Ctrl-D)
                break;
            }
            Err(e) => {
                eprintln!("Readline error: {:?}", e);
                break;
            }
        }
    }

    // Clean up: kill the child and save history
    child.kill().await.expect("Failed to kill child");
    let _ = rl.save_history("history.txt");

    Ok(())
}
