  "main.rs": "use std::future::Future;
use std::marker::Unpin;
use std::pin::Pin;
use std::task::{Context, Poll};
use futures::task::noop_waker;

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Tries to poll a future to completion without yielding.
/// Returns `Ready(x)` if the future completed synchronously, otherwise `Pending`.
fn try_poll<X>(future: &mut (impl Future<Output = X> + Unpin)) -> TryPollResult<X> {
    // Create a no‑op waker. This is sufficient for a "try once" poll;
    // the future won't be woken automatically, but we only care about
    // whether it can make progress right now.
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    // Pin the future (impl Future + Unpin satisfies Pin)
    let pinned = Pin::new(future);
    match pinned.poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    // Example: a future that completes immediately
    let mut future_immediate = async { 42 };

    // Try to poll it synchronously
    match try_poll(&mut future_immediate) {
        TryPollResult::Ready(val) => {
            println!("Polled directly and got: {}", val);
        }
        TryPollResult::Pending => {
            // Should not happen for this particular future
            eprintln!("Unexpected pending result for immediate future");
        }
    }

    // Example: a future that returns Pending the first time we poll it
    struct DelayFuture {
        duration: std::time::Duration,
        start: std::time::Instant,
    }

    impl Future for DelayFuture {
        type Output = &'static str;
        fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
            let this = self.get_mut();
            if this.start.elapsed() >= this.duration {
                Poll::Ready("delayed result")
            } else {
                // Register a wakeup (just for illustration)
                cx.waker().wake_by_ref();
                Poll::Pending
            }
        }
    }

    // We'll make a future that yields on the first poll and then completes.
    let mut delay_future = DelayFuture {
        duration: std::time::Duration::from_millis(10),
        start: std::time::Instant::now(),
    };

    // First poll: should be Pending because the delay hasn't elapsed.
    match try_poll(&mut delay_future) {
        TryPollResult::Ready(_) => {
            // Should not happen – the delay hasn't passed yet
            eprintln!("Unexpected ready result");
        }
        TryPollResult::Pending => {
            println!("Future was not ready, spawning a task to wait for it...");
            // Spawn a task that will actually wait for the future.
            // We move the future into the async block; the runtime will
            // poll it again when the waker is notified.
            tokio::spawn(async move {
                let result = delay_future.await;
                println!("Spawned task got: {}", result);
            })
            .await
            .expect("spawned task panicked");
        }
    }

    // Keep the runtime alive a bit to let the spawned task finish.
    // In a real program you would let the runtime run naturally.
    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
    println!("Program finished.");
}
"
