/// The Agent struct is owned by the Tauri state.
/// It holds a Sender to communicate with the background PTY thread.
pub struct Agent {
    cmd_tx: channel::Sender<String>,
}

impl Agent {
    /// Spawns the PTY process and starts the event loop.
    /// Returns the Agent handle and an output receiver for events.
    pub fn spawn(
        program: &str,
        args: Vec<&str>,
        cwd: Option<&str>,
    ) -> Result<(Self, channel::Receiver<String>), String> {
        let (cmd_tx, cmd_rx) = channel::unbounded();
        let (out_tx, out_rx) = channel::unbounded();

        // Spawn the worker thread that owns the PTY session
        std::thread::spawn(move || {
            if let Err(e) = run_pty_loop(program, args, cwd, cmd_rx, out_tx) {
                log::error!("PTY Loop Error: {}", e);
                let _ = out_tx.send("[Process terminated due to error]\r\n".to_string());
            }
        });

        Ok((Agent { cmd_tx }, out_rx))
    }

    /// The method called by your Tauri command.
    /// It is non-blocking; it simply sends data to the worker thread.
    pub fn send(&self, data: &str) -> Result<(), String> {
        self.cmd_tx
            .send(data.to_string()).map_err(|_| "Agent thread disconnected".into())
    }
}

/// The event loop running in the background thread.
/// It uses `crossbeam::select!` to wait on either user input (from Tauri)
/// or PTY output, preventing the deadlock described in the prompt.
fn run_pty_loop(
    program: &str,
    args: Vec<&str>,
    cwd: Option<&str>,
    rx: channel::Receiver<String>,
    tx: channel::Sender<String>,
) -> Result<(), Box<dyn std::error::Error>> {
    let pty_system = native_pty_system();

    let pair = pty_system.openpty(PtySize {
        rows: 24,
        cols: 80,
        pixel_width: 0,
        pixel_height: 0,
    })?;

    let mut cmd = CommandBuilder::new(program);
    cmd.args(args);
    if let Some(dir) = cwd {
        cmd.cwd(dir);
    }
    // Set environment for better TUI support
    cmd.env("TERM", "xterm-256color");

    let mut child = pair.slave.spawn_command(cmd)?;
    let mut session = Session::new(pair.master)?;

    // Take the reader/writer handles to avoid borrowing the session immutably
    // in a way that conflicts, though the Select loop handles the mutability.
    let mut read_buf = [0u8; 2048];

    // Set raw mode if needed, though expectrl usually handles this.
    // session.set_raw_mode()?; 

    loop {
        // 1. Select: Wait for either a command from the UI OR a timeout.
        // We use a timeout for reading to ensure we cycle often enough.
        crossbeam::select! {
            // CASE A: User sent data (Keystrokes/Lines)
            recv(rx) -> msg => {
                match msg {
                    Ok(data) => {
                        // Write user input to PTY
                        // We ignore write errors here for simplicity, 
                        // but proper error handling would involve checking flow control.
                        let _ = session.write_all(data.as_bytes());
                        // Ensure flush so the process sees it immediately
                        let _ = session.flush();
                    }
                    Err(_) => break, // Channel closed, exit loop
                }
            }
            // CASE B: Check for PTY output (with a short timeout)
            default(Duration::from_millis(50)) => {
                // Try to read non-blocking-ish
                // Note: expectrl::Session::read is blocking. We use the timeout
                // above to approximate non-blocking behavior in the select loop.
                match session.read(&mut read_buf) {
                    Ok(0) => {
                        // EOF
                        tx.send("\r\n[Process finished]\r\n".to_string()).ok();
                        break;
                    }
                    Ok(n) => {
                        let output = String::from_utf8_lossy(&read_buf[..n]).to_string();
                        // Send output to the frontend receiver
                        tx.send(output).ok();
                    }
                    Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                        // Normal timeout behavior, just continue loop
                    }
                    Err(e) => {
                        log::error!("Read error: {}", e);
                        break;
                    }
                }
            }
        }
    }

    child.wait()?;
    Ok(())
}


