  "main.rs": "use serde::{Deserialize, Deserializer, Serialize};
use serde::de::{MapAccess, Visitor, IgnoredAny};
use std::fmt;

#[derive(Serialize, Deserialize, Debug, Clone, PartialEq)]
enum B {
    Something(String),
    Other(i32),
}

#[derive(Serialize, Debug, Default, Clone, PartialEq)]
