    assert_eq!(a.b.len(), 2);
    if let B::Something(ref s) = a.b[0] {
        assert_eq!(s, "hello");
    }
    if let B::Other(ref n) = a.b[1] {
        assert_eq!(*n, 123);
    }

    // Serialize back to JSON and check that we can deserialize again.
    let serialized = serde_json::to_string(&a).expect("failed to serialize");
    let a2: A = serde_json::from_str(&serialized).expect("failed to deserialize round‑trip");
    assert_eq!(a, a2);

    // If we reach here, all tests passed.
