// ---------- Derive macro for #[derive(NotionProperty)] ----------

use proc_macro::TokenStream;
use quote::quote;
use syn::{parse_macro_input, DeriveInput, Data, Meta, MetaNameValue, Lit};

#[proc_macro_derive(NotionProperty, attributes(notion_property))]
pub fn notion_property_derive(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let name = &input.ident;

    let fields = match &input.data {
        Data::Struct(s) => &s.fields,
        _ => panic!("NotionProperty can only be derived for structs"),
    };

    let mut field_infos = Vec::new();

    for field in fields.iter() {
        let field_ident = field.ident.as_ref().expect("Named field expected");
        let ty = &field.ty;
        let is_option = match ty {
            syn::Type::Path(ref tp) => {
                tp.path.segments.iter().any(|seg| seg.ident == "Option")
            }
            _ => false,
        };

