                    if let Meta::NameValue(nv) = nested {
                        if nv.path.is_ident("type") {
                            if let Lit::Str(lit_str) = &nv.lit {
                                prop_type = Some(lit_str.value());
                            }
                        } else if nv.path.is_ident("name") {
                            if let Lit::Str(lit_str) = &nv.lit {
                                prop_name = Some(lit_str.value());
                            }
                        }
                    }
                }
            }
        }

        if let (Some(t), Some(n)) = (prop_type, prop_name) {
            field_infos.push((field_ident, t, n, is_option));
        }
    }

    let inserts: Vec<_> = field_infos
        .iter()
        .map(|(field_ident, prop_type, prop_name, is_option)| {
            match prop_type.as_str() {
                "title" => {
                    if *is_option {
                        quote! {
                            if let Some(ref #field_ident) = self.#field_ident {
                                map.insert(
                                    #prop_name.to_string(),
                                    PropertyValue::Title(vec![RichTextObject {
                                        annotations: None,
                                        data_type: Some(RichTextType::Text),
                                        equation: None,
                                        mention: None,
                                        plain_text: None,
                                        href: None,
                                        text: TextObject {
                                            content: #field_ident.clone(),
                                            link: None,
                                        },
                                    }]),
                                );
                            }
                        }
                    } else {
                        quote! {
                            map.insert(
                                #prop_name.to_string(),
                                PropertyValue::Title(vec![RichTextObject {
                                    annotations: None,
                                    data_type: Some(RichTextType::Text),
                                    equation: None,
                                    mention: None,
                                    plain_text: None,
                                    href: None,
                                    text: TextObject {
                                        content: self.#field_ident.clone(),
                                        link: None,
                                    },
                                }]),
                            );
                        }
                    }
                }
                "url" => {
                    if *is_option {
                        quote! {
                            if let Some(ref #field_ident) = self.#field_ident {
                                map.insert(#prop_name.to_string(), PropertyValue::Url(#field_ident.clone()));
                            }
                        }
                    } else {
                        quote! {
                            map.insert(#prop_name.to_string(), PropertyValue::Url(self.#field_ident.clone()));
                        }
                    }
                }
                "multi_select" => {
                    if *is_option {
                        quote! {
                            if let Some(ref #field_ident) = self.#field_ident {
                                let __sel: Vec<SelectObject> = #field_ident
                                    .iter()
                                    .map(|__e| SelectObject {
                                        id: None,
                                        color: None,
                                        name: __e.as_str().map(|s| s.to_string()).unwrap_or_default(),
                                    })
                                    .collect();
                                map.insert(#prop_name.to_string(), PropertyValue::MultiSelect(__sel));
                            }
                        }
                    } else {
                        quote! {
                            let __sel: Vec<SelectObject> = self.#field_ident
                                .iter()
                                .map(|__e| SelectObject {
                                    id: None,
                                    color: None,
                                    name: __e.as_str().map(|s| s.to_string()).unwrap_or_default(),
                                })
                                .collect();
                            map.insert(#prop_name.to_string(), PropertyValue::MultiSelect(__sel));
                        }
                    }
                }
                _ => {
                    // Unknown type – skip
                    quote! {}
                }
            }
        })
        .collect();

    let (impl_gens, ty_gens, where_clause) = input.generics.split_for_impl();

    let tokens = quote! {
        impl #impl_gens NotionMap for #name #ty_gens #where_clause {
            fn to_notion_map(&self) -> std::collections::HashMap<String, PropertyValue> {
                let mut map = std::collections::HashMap::new();
                #(#inserts)*
                map
            }
        }
    };

    tokens.into()
