const ALLOWED_ORIGIN: &str = "https://www.example.com";

/// Middleware that checks the Origin header for WebSocket requests
async fn check_origin_header(mut req: axum::extract::Request<Body>, next: axum::middleware::Next) -> impl IntoResponse {
    let origin = req
        .headers()
        .get("origin")
        .and_then(|v| v.to_str().ok());

    match origin {
        Some(o) if o == ALLOWED_ORIGIN => next.run(req).await,
        _ => (StatusCode::FORBIDDEN, "Origin not allowed"),
    }
}

/// WebSocket handler
async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    println!("Received WebSocket upgrade request for session: {}", session_id);

    ws.on_upgrade(|socket| handle_socket(socket))
}

/// Handle WebSocket messages
async fn handle_socket(mut socket: WebSocket) {
    while let Some(msg) = socket.recv().await {
        if let Ok(msg) = msg {
            match msg {
                Message::Text(text) => {
                    println!("Received text: {}", text);
                    if socket.send(Message::Text(format!("Echo: {}", text))).await.is_err() {
                        break;
                    }
                }
                Message::Close(_) => {
                    println!("Client disconnected");
                    break;
                }
                _ => {}
            }
        } else {
            break;
        }
    }
}

#[tokio::main]
