                current = map.get(part)?.clone();
            }
            Value::Array(arr) => {
                let index: usize = part.parse().ok()?;
                current = arr.get(index)?.clone();
            }
            _ => return None,
        }
    }

    Some(current)
}

fn resolve_ref(ref_str: &str, base_path: &Path) -> Result<Value, Box<dyn std::error::Error>> {
