  "main.rs": "/// Shell command tokenizer that respects single quotes.
/// 
/// Splits a command string into tokens following bash shell semantics:
/// - Text outside quotes is split on whitespace
/// - Text inside single quotes is preserved verbatim (including spaces)
/// - Adjacent quoted and unquoted segments are concatenated
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens: Vec<String> = Vec::new();
    let mut current = String::new();
    let mut in_quotes = false;
    let mut chars = input.chars().peekable();

    while let Some(ch) = chars.next() {
        match ch {
            '\'' => {
                // Toggle quote state
                in_quotes = !in_quotes;
            }
            ' ' if !in_quotes => {
                // Outside quotes: space ends current token
                if !current.is_empty() {
                    // Split current token on whitespace (handles multiple spaces)
                    tokens.extend(
                        current
                            .split_whitespace()
                            .map(|s| s.to_string())
                    );
                    current.clear();
                }
            }
            _ => {
                current.push(ch);
            }
        }
    }

    // Don't forget the last token
    if !current.is_empty() {
        if in_quotes {
            // Unclosed quote - treat as literal
            tokens.push(current);
        } else {
            tokens.extend(
                current
                    .split_whitespace()
                    .map(|s| s.to_string())
            );
        }
    }

    // Join adjacent quoted and unquoted tokens
    // e.g., "' two '" + "three" -> " two  three"
    let mut result: Vec<String> = Vec::new();
    let mut pending: Option<String> = None;

    for token in tokens {
        if let Some(prev) = pending.take() {
            // Check if previous token ended with quote or current starts with quote-like pattern
            // In our simple case, we concatenate any adjacent tokens
            pending = Some(prev + &token);
        } else if result.last().map(|last| last.ends_with('\'')).unwrap_or(false) {
            // Previous token was quoted, concatenate with current
            if let Some(prev) = result.pop() {
                pending = Some(prev + &token);
            } else {
                result.push(token);
            }
        } else {
            result.push(token);
        }
    }

    if let Some(remaining) = pending {
        result.push(remaining);
    }

    result
}

fn main() {
    let test_input = " one  ' two  'three    four";

    println!("Input: {:?}", test_input);
    println!("Tokens:");

    for (i, token) in tokenize(test_input).iter().enumerate() {
        println!("  {}: {:?}", i, token);
    }

    // Expected output based on bash:
    // one, " two  three", four
    println!("\nExpected: \"one\", \" two  three\", \"four\"");
}

