    // tile(nrows, 1) repeats the row vector vertically nrows times.
    let mean_broadcast = mean_row.tile(matrix.nrows(), 1);

    // Subtract the column means from each column (i.e., from each row).
    let centered = matrix - mean_broadcast;

    println!("Original matrix:\n{}", matrix);
    println!("Column means (row vector):\n{}", mean_row);
    println!("Centered matrix:\n{}", centered);
}
