type FlusterResult<T> = Result<T, FlusterError>;

/// Parse a LanceDB formatted ISO date string (with optional fractional seconds)
/// into a Unix timestamp (seconds since epoch).
pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    // Two format strings: one expects a fractional part, the other does not.
    const FMT_WITH_FRAC: &str = "%Y-%m-%dT%H:%M:%S%.f";
    const FMT_NO_FRAC: &str = "%Y-%m-%dT%H:%M:%S";

    // Try the format with fractional seconds first.
    let naive = match NaiveDateTime::parse_from_str(d, FMT_WITH_FRAC) {
        Ok(dt) => dt,
        Err(_) => {
            // If that fails, try without the fractional part.
            NaiveDateTime::parse_from_str(d, FMT_NO_FRAC)
                .map_err(|_| FlusterError::FailToParseDate)?
        }
    };

    // Treat the parsed naive datetime as UTC and convert to a Unix timestamp.
    let dt = naive.and_utc();
    Ok(dt.timestamp())
}

