/// Create a POSIX shared memory region of the given size and return
/// the file descriptor and a pointer to the mapped memory.
fn create_shmem(name: &CString, size: usize) -> (i32, *mut u8) {
    let fd = unsafe {
        shm_open(
            name.as_ptr(),
            O_RDWR | O_CREAT | O_EXCL,
            S_IRUSR | S_IWUSR,
        )
    };
