    }

    let ret = unsafe { ftruncate(fd, size as libc::off_t) };
    if ret == -1 {
        close(fd);
        panic!("Failed to truncate shared memory: {}", std::io::Error::last_os_error());
    }

    let ptr = unsafe {
        mmap(
            ptr::null_mut(),
            size,
            PROT_READ | PROT_WRITE,
            MAP_SHARED,
            fd,
            0,
        )
    };
    if ptr == libc::MAP_FAILED {
        close(fd);
        panic!("Failed to mmap shared memory: {}", std::io::Error::last_os_error());
    }

    (fd, ptr as *mut u8)
}

/// Guard that will unlink the shared memory object when dropped.
struct ShmGuard(CString);

impl Drop for ShmGuard {
    fn drop(&mut self) {
        unsafe {
            shm_unlink(self.0.as_ptr());
        }
    }
}

