    let shm_name = CString::new(format!("/kitty_anim_{}", std::process::id()))
        .expect("Failed to create CString for shm name");

    // Create the shared memory region.
    let (fd, shm_ptr) = create_shmem(&shm_name, size);

    // The file descriptor can be closed once the region is mapped; the mapping remains valid.
    unsafe { close(fd); }

    // Create a mutable slice we can write pixel data into.
    let buf = unsafe { std::slice::from_raw_parts_mut(shm_ptr, size) };

    // Ensure the shared memory is cleaned up when the program exits.
    let _guard = ShmGuard(shm_name.clone());

    // Lock stdout once for the whole animation.
    let stdout = io::stdout();
    let mut handle = stdout.lock();

    // Timing to target roughly 60 FPS.
    let target_frame_time = Duration::from_nanos(1_000_000_000 / 60);
    let mut last_frame = Instant::now();

    // Animation state.
    let mut time: f32 = 0.0;
    let mut first_frame = true;

    loop {
        // Sleep to maintain frame rate.
        let now = Instant::now();
        let elapsed = now.duration_since(last_frame);
        if elapsed < target_frame_time {
            thread::sleep(target_frame_time - elapsed);
        }
        last_frame = Instant::now();

