// ============================================================================
// Trait definition
// ============================================================================

/// Trait that expresses “does the filter match the receiver?”.
/// For leaf types it is just equality; for container types it performs a
/// field‑wise partial match.
pub trait Matches {
    fn matches(&self, filter: &Self) -> bool;
}

// ============================================================================
// Helper macros
// ============================================================================

/// Macro to implement `Matches` for primitive / enum types that already implement
/// `PartialEq`.  This covers `bool`, integer types, `char`, `&str`, `String`, etc.
macro_rules! impl_matches_prim {
    ($($ty:ty),*) => {$(
        impl Matches for $ty {
            fn matches(&self, filter: &Self) -> bool {
                self == filter
            }
        }
    )*}
}

/// Macro that generates a `Matches` implementation for a struct.  It assumes that
/// **both** the target struct and the filter struct have the same field names and
/// that every filter field is wrapped in `Option`.  For each field it checks
/// `if let Some(ref f) = filter.field` and then calls `self.field.matches(f)`.
/// This gives us recursion for free.
macro_rules! impl_matches_struct {
    ($ty:ty, [ $($field:ident),* $(,)? ]) => {
        impl Matches for $ty {
            fn matches(&self, filter: &Self) -> bool {
                $(
                    if let Some(ref f_val) = filter.$field {
                        let s_val = &self.$field;
                        if !s_val.matches(f_val) {
                            return false;
                        }
                    }
                )*
                true
            }
        }
    };
