response:
Looking at the code, the issue is that `.repeated()` in Chumsky returns a parser that emits `()` by default. To get the actual collected results as a `Vec`, you need to call `.collect()` after `.repeated()`.

Here's the fix - I've added `.collect()` to the repeated parser and made a few minor adjustments for it to compile cleanly:

```json
{
  "Cargo.toml": "[package]
name = "chumsky_example"
version = "0.1.0"
edition = "2021"

[dependencies]
chumsky = "0.6"",
  "main.rs": "use chumsky::prelude::*;
use chumsky::text;

#[derive(Debug, Clone)]
pub enum BinOp {
    Mul,
    Div,
}

#[derive(Debug, Clone)]
pub enum Expr {
    Int(i32),
    Binary {
        left: Box<Expr>,
        op: BinOp,
        right: Box<Expr>,
    },
}

fn parse_mul_op<'a>() -> impl Parser<'a, &'a str, BinOp> {
    just('*').to(BinOp::Mul)
        .or(just('/').to(BinOp::Div))
}

fn parse_primary<'a>() -> impl Parser<'a, &'a str, Expr> {
    text::int(10).map(|s: &str| Expr::Int(s.parse().unwrap()))
}

fn parse_mul_div<'a>() -> impl Parser<'a, &'a str, Expr> {
    let lhs = parse_primary();
    let op_rhs = parse_mul_op().then(parse_primary());

    lhs
        .then(op_rhs.repeated().collect())
        .map(|(mut expr, tail)| {
            for (op, rhs) in tail {
                expr = Expr::Binary {
                    left: Box::new(expr),
                    op,
                    right: Box::new(rhs),
                };
            }
            expr
        })
}

fn main() {
    let parser = parse_mul_div();
    let result = parser.parse("1*2*3");
    println!("{:?}", result);
}"
}
```

