/// Optimized blob processing with concurrency control
async fn process_blobs(
    container_client: &ContainerClient,
    prefix: String,
) -> Result<Vec<TradeData>, String> {
    if prefix.is_empty() {
        return Ok(vec![]);
    }

    let mut all_trades = Vec::new();

    // LIMIT CONCURRENCY:
    // The C# code uses Parallel.ForEachAsync with Environment.ProcessorCount.
    // However, for network I/O, we can usually handle much more (e.g., 50-100) without overwhelming the OS/Network.
    // Using a Semaphore ensures we don't open 1000 sockets at once, which can cause throttling or context switching overhead.
    let concurrency_limit = 100;
    let semaphore = Arc::new(Semaphore::new(concurrency_limit));

    // Stream through blob pages
    let mut stream = container_client.list_blobs().prefix(prefix.clone()).into_stream();

    while let Some(response) = stream.next().await {
        let response = response.map_err(|e| format!("List error: {}", e))?;

        // Collect futures for this page
        let mut futures = futures::stream::FuturesUnordered::new();

        for blob in response.blobs.blobs() {
            if blob.name.ends_with(".json") {
                let blob_client = container_client.blob_client(&blob.name);
                let sem = semaphore.clone();

                futures.push(async move {
                    // Acquire permit before starting work
                    let permit = sem.acquire_owned().await.expect("Semaphore closed");

                    let result: Result<Option<TradeData>, String> = async {
                        let data = blob_client
                            .get_content()
                            .await
                            .map_err(|e| format!("Download error: {}", e))?;

                        let parsed = serde_json::from_slice::<TradeData>(&data)
                            .map_err(|e| format!("Parse error: {}", e))?;

                        Ok(Some(parsed))
                    }.await;

                    // Explicitly drop permit when done
                    drop(permit);
                    result
                });
            }
        }

        // Wait for this page to finish
        while let Some(result) = futures.next().await {
            match result {
                Ok(Some(trade)) => all_trades.push(trade),
                Ok(None) => {}
                Err(e) => eprintln!("Blob error: {}", e),
            }
        }
    }

    Ok(all_trades)
}
