fn rotate_cube(time: Res<Time>, mut query: Query<&mut Transform, With<Cube>>) {
    for mut transform in query.iter_mut() {
        let t = time.elapsed_seconds();
        let rot_y = Quat::from_rotation_y(t * 0.5);
        let rot_x = Quat::from_rotation_x(t * 0.3);
        transform.rotation = rot_y * rot_x;
    }
}

fn draw_face_gizmos(mut gizmos: Gizmos, query: Query<&Transform, With<Cube>>) {
    let Ok(transform) = query.get_single() else { return };
    let q = transform.rotation;

    let local_normals = [
        Vec3::X,
        Vec3::NEG_X,
        Vec3::Y,
        Vec3::NEG_Y,
        Vec3::Z,
        Vec3::NEG_Z,
    ];

    for &local_normal in local_normals.iter() {
        let n = (q * local_normal).normalize();
        let face_center = transform.translation + (q * (local_normal * 0.5));
        let rotation = compute_face_rotation(transform, local_normal);
        let offset = n * 0.01;
        let isometry = Transform::from_translation(face_center + offset)
            .with_rotation(rotation)
            .to_isometry();
        gizmos.rect(isometry, Vec2::splat(0.5), Color::WHITE);
    }
}

fn compute_face_rotation(block_transform: &Transform, local_normal: Vec3) -> Quat {
    let q = block_transform.rotation();

    // Choose a local tangent that lies in the plane of the face.
    let tangent_local = if local_normal.abs().x > 0.9 {
        Vec3::Y
    } else if local_normal.abs().y > 0.9 {
        Vec3::Z
    } else {
        Vec3::X
    };

    // Compute local bitangent (cross product yields orthonormal vector)
    let bitangent_local = local_normal.cross(tangent_local);

    // Transform to world space
    let tangent = (q * tangent_local).normalize();
    let bitangent = (q * bitangent_local).normalize();
    let normal = (q * local_normal).normalize();

    // Build rotation matrix from the three axes
    let rotation_matrix = Mat3::from_cols(tangent, bitangent, normal);

    Quat::from_rotation_mat3(&rotation_matrix)
}
